import { describe, it, expect, vi, beforeEach } from 'vitest'

// Mock de next/navigation
const mockRedirect = vi.fn()
vi.mock('next/navigation', () => ({
  redirect: (...args: unknown[]) => {
    mockRedirect(...args)
    throw new Error('NEXT_REDIRECT')
  },
}))

// Mock de supabase server client
const mockGetUser = vi.fn()
vi.mock('@/lib/supabase/server', () => ({
  createSupabaseServerClient: vi.fn().mockResolvedValue({
    auth: { getUser: () => mockGetUser() },
  }),
}))

// Mock de prisma para getOrCreateDbUser
const { mockUpsert } = vi.hoisted(() => ({
  mockUpsert: vi.fn().mockResolvedValue({ id: 'db-user-1', name: 'Test User' }),
}))
vi.mock('@/lib/db', () => ({
  prisma: { user: { upsert: mockUpsert } },
}))

// Import after mocks
import { getSession, getSessionWithRole, requireAuth, requireRole, getOrCreateDbUser } from '../auth'

describe('auth utilities', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  // ── getSession ──

  describe('getSession()', () => {
    it('retorna el usuario si esta autenticado', async () => {
      const user = { id: 'u1', email: 'test@test.com' }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await getSession()
      expect(result).toEqual(user)
    })

    it('retorna null si no hay usuario', async () => {
      mockGetUser.mockResolvedValue({ data: { user: null } })

      const result = await getSession()
      expect(result).toBeNull()
    })
  })

  // ── getSessionWithRole ──

  describe('getSessionWithRole()', () => {
    it('retorna usuario con rol de app_metadata', async () => {
      const user = { id: 'u1', email: 'a@b.com', app_metadata: { role: 'admin' } }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await getSessionWithRole()
      expect(result).toEqual({ user, role: 'admin' })
    })

    it('retorna role "parent" por defecto si no hay app_metadata.role', async () => {
      const user = { id: 'u2', email: 'b@b.com', app_metadata: {} }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await getSessionWithRole()
      expect(result?.role).toBe('parent')
    })

    it('retorna role "parent" si app_metadata es undefined', async () => {
      const user = { id: 'u3', email: 'c@c.com' }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await getSessionWithRole()
      expect(result?.role).toBe('parent')
    })

    it('retorna null si no hay usuario', async () => {
      mockGetUser.mockResolvedValue({ data: { user: null } })

      const result = await getSessionWithRole()
      expect(result).toBeNull()
    })
  })

  // ── requireAuth ──

  describe('requireAuth()', () => {
    it('retorna usuario si esta autenticado', async () => {
      const user = { id: 'u1', email: 'test@test.com' }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await requireAuth()
      expect(result).toEqual(user)
      expect(mockRedirect).not.toHaveBeenCalled()
    })

    it('redirige a /login si no hay sesion', async () => {
      mockGetUser.mockResolvedValue({ data: { user: null } })

      await expect(requireAuth()).rejects.toThrow('NEXT_REDIRECT')
      expect(mockRedirect).toHaveBeenCalledWith('/login')
    })
  })

  // ── requireRole ──

  describe('requireRole()', () => {
    it('retorna sesion si el usuario tiene el rol requerido (ADMIN)', async () => {
      const user = { id: 'u1', email: 'admin@test.com', app_metadata: { role: 'admin' } }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await requireRole(['ADMIN'])
      expect(result).toEqual({ user, role: 'admin' })
    })

    it('redirige a / si el usuario no tiene el rol requerido', async () => {
      const user = { id: 'u2', email: 'user@test.com', app_metadata: { role: 'parent' } }
      mockGetUser.mockResolvedValue({ data: { user } })

      await expect(requireRole(['ADMIN'])).rejects.toThrow('NEXT_REDIRECT')
      expect(mockRedirect).toHaveBeenCalledWith('/')
    })

    it('redirige a /login si no hay sesion', async () => {
      mockGetUser.mockResolvedValue({ data: { user: null } })

      await expect(requireRole(['ADMIN'])).rejects.toThrow('NEXT_REDIRECT')
      expect(mockRedirect).toHaveBeenCalledWith('/login')
    })

    it('acepta multiples roles (ADMIN o MODERATOR)', async () => {
      const user = { id: 'u3', email: 'mod@test.com', app_metadata: { role: 'moderator' } }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await requireRole(['ADMIN', 'MODERATOR'])
      expect(result).toEqual({ user, role: 'moderator' })
    })

    it('rol desconocido se trata como PARENT', async () => {
      const user = { id: 'u4', email: 'x@test.com', app_metadata: { role: 'superuser' } }
      mockGetUser.mockResolvedValue({ data: { user } })

      // Si pide ADMIN, un rol desconocido (mapeado a PARENT) no pasa
      await expect(requireRole(['ADMIN'])).rejects.toThrow('NEXT_REDIRECT')
      expect(mockRedirect).toHaveBeenCalledWith('/')
    })

    it('rol desconocido pasa si PARENT esta en los roles permitidos', async () => {
      const user = { id: 'u5', email: 'y@test.com', app_metadata: { role: 'unknown' } }
      mockGetUser.mockResolvedValue({ data: { user } })

      const result = await requireRole(['PARENT'])
      expect(result).toEqual({ user, role: 'unknown' })
    })
  })

  // ── getOrCreateDbUser ──

  describe('getOrCreateDbUser()', () => {
    beforeEach(() => mockUpsert.mockResolvedValue({ id: 'db-1', name: 'Test' }))

    it('usa full_name de user_metadata cuando está disponible', async () => {
      const authUser = {
        id: 'auth-1',
        email: 'a@b.com',
        user_metadata: { full_name: 'Juan Pérez', name: 'Juan' },
      } as any

      await getOrCreateDbUser(authUser)

      const createArg = mockUpsert.mock.calls[0][0].create
      expect(createArg.name).toBe('Juan Pérez')
    })

    it('usa user_metadata.name si no hay full_name', async () => {
      const authUser = {
        id: 'auth-2',
        email: 'b@c.com',
        user_metadata: { name: 'María' },
      } as any

      await getOrCreateDbUser(authUser)

      const createArg = mockUpsert.mock.calls[0][0].create
      expect(createArg.name).toBe('María')
    })

    it('usa la parte local del email si no hay user_metadata.name', async () => {
      const authUser = {
        id: 'auth-3',
        email: 'carlos@example.com',
        user_metadata: {},
      } as any

      await getOrCreateDbUser(authUser)

      const createArg = mockUpsert.mock.calls[0][0].create
      expect(createArg.name).toBe('carlos')
    })

    it('usa "Usuario" como fallback si no hay ningún dato de nombre', async () => {
      const authUser = {
        id: 'auth-4',
        email: undefined,
        user_metadata: {},
      } as any

      await getOrCreateDbUser(authUser)

      const createArg = mockUpsert.mock.calls[0][0].create
      expect(createArg.name).toBe('Usuario')
    })

    it('llama upsert con supabaseAuthId correcto y rol PARENT', async () => {
      const authUser = {
        id: 'auth-5',
        email: 'x@y.com',
        user_metadata: { full_name: 'Test' },
      } as any

      await getOrCreateDbUser(authUser)

      expect(mockUpsert).toHaveBeenCalledWith(
        expect.objectContaining({
          where: { supabaseAuthId: 'auth-5' },
          create: expect.objectContaining({ role: 'PARENT', supabaseAuthId: 'auth-5' }),
        })
      )
    })
  })
})

// =============================================================================
// Tests: lib/cities.ts — getCitiesForSelector
//
// Lógica de negocio crítica: dual-count (strictCount gate + orCount visible),
// filtro de badDomains y transformación de tipos Prisma → CityOption.
//
// Estrategia: mock del singleton prisma de lib/db para testear sin BD real.
// =============================================================================

import { describe, it, expect, vi, beforeEach } from 'vitest';

// ── Mocks con vi.hoisted ──────────────────────────────────────────────────────
const mocks = vi.hoisted(() => {
  const mockCityFindMany    = vi.fn();
  const mockSourceFindMany  = vi.fn();
  const mockActivityCount   = vi.fn();

  return { mockCityFindMany, mockSourceFindMany, mockActivityCount };
});

vi.mock('../../lib/db', () => ({
  prisma: {
    city:         { findMany: mocks.mockCityFindMany },
    sourceHealth: { findMany: mocks.mockSourceFindMany },
    activity:     { count:    mocks.mockActivityCount },
  },
}));

// buildActivityWhere es una función pura — no necesita mock
import { getCitiesForSelector } from '../../lib/cities';

// ── Fixtures ──────────────────────────────────────────────────────────────────
const BOG = {
  id: 'city-bog',
  name: 'Bogotá',
  defaultLat: 4.711,
  defaultLng: -74.0721,
  defaultZoom: 12,
};

const MED = {
  id: 'city-med',
  name: 'Medellín',
  defaultLat: 6.2442,
  defaultLng: -75.5812,
  defaultZoom: 12,
};

// =============================================================================
// Gate: strictCount ≥ 1 — ciudades fantasma excluidas
// =============================================================================
describe('getCitiesForSelector — gate strictCount', () => {
  beforeEach(() => vi.clearAllMocks());

  it('excluye ciudades donde strictCount = 0 (ciudad fantasma)', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    // strictCount = 0, orCount = 5
    mocks.mockActivityCount
      .mockResolvedValueOnce(0)  // strictCount BOG
      .mockResolvedValueOnce(5); // orCount BOG

    const result = await getCitiesForSelector();
    expect(result).toHaveLength(0);
  });

  it('incluye ciudad donde strictCount ≥ 1', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(3)  // strictCount BOG
      .mockResolvedValueOnce(10); // orCount BOG

    const result = await getCitiesForSelector();
    expect(result).toHaveLength(1);
    expect(result[0].id).toBe('city-bog');
  });

  it('filtra solo las ciudades fantasma — mantiene las que tienen supply', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG, MED]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(5)  // strictCount BOG ✓
      .mockResolvedValueOnce(20) // orCount BOG
      .mockResolvedValueOnce(0)  // strictCount MED ✗ (fantasma)
      .mockResolvedValueOnce(3); // orCount MED (no importa — se filtra)

    const result = await getCitiesForSelector();
    expect(result).toHaveLength(1);
    expect(result[0].id).toBe('city-bog');
  });
});

// =============================================================================
// activityCount visible = orCount (no strictCount)
// =============================================================================
describe('getCitiesForSelector — activityCount usa orCount', () => {
  beforeEach(() => vi.clearAllMocks());

  it('el activityCount visible es orCount, no strictCount', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(3)   // strictCount (gate)
      .mockResolvedValueOnce(42); // orCount (número visible)

    const [city] = await getCitiesForSelector();
    expect(city.activityCount).toBe(42);
  });
});

// =============================================================================
// Transformación de tipos — Prisma Decimal → Number
// =============================================================================
describe('getCitiesForSelector — tipos de salida', () => {
  beforeEach(() => vi.clearAllMocks());

  it('defaultLat y defaultLng se convierten a Number (desde Prisma Decimal)', async () => {
    const cityWithDecimal = {
      ...BOG,
      defaultLat: { toNumber: () => 4.711 } as any, // simula Prisma Decimal
      defaultLng: { toNumber: () => -74.0721 } as any,
    };
    mocks.mockCityFindMany.mockResolvedValue([cityWithDecimal]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(1)
      .mockResolvedValueOnce(10);

    const [city] = await getCitiesForSelector();
    // Number() sobre un Decimal de Prisma llama .valueOf() — verificamos que sea numérico
    expect(typeof city.defaultLat).toBe('number');
    expect(typeof city.defaultLng).toBe('number');
  });

  it('retorna los campos correctos en cada CityOption', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(2)
      .mockResolvedValueOnce(15);

    const [city] = await getCitiesForSelector();
    expect(city).toMatchObject({
      id:           'city-bog',
      name:         'Bogotá',
      defaultZoom:  12,
      activityCount: 15,
    });
  });
});

// =============================================================================
// Sin ciudades activas — retorna array vacío
// =============================================================================
describe('getCitiesForSelector — sin ciudades', () => {
  beforeEach(() => vi.clearAllMocks());

  it('retorna [] si no hay ciudades activas en BD', async () => {
    mocks.mockCityFindMany.mockResolvedValue([]);
    mocks.mockSourceFindMany.mockResolvedValue([]);

    const result = await getCitiesForSelector();
    expect(result).toEqual([]);
    expect(mocks.mockActivityCount).not.toHaveBeenCalled();
  });

  it('retorna [] si todas las ciudades son fantasma (strictCount = 0)', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG, MED]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount.mockResolvedValue(0); // strictCount = 0 para todas

    const result = await getCitiesForSelector();
    expect(result).toEqual([]);
  });
});

// =============================================================================
// badDomains — integración con filtro de calidad
// =============================================================================
describe('getCitiesForSelector — badDomains', () => {
  beforeEach(() => vi.clearAllMocks());

  it('pasa badDomains al orCount (buildActivityWhere) cuando hay fuentes degradadas', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG]);
    mocks.mockSourceFindMany.mockResolvedValue([{ source: 'spam.com' }]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(5)  // strictCount
      .mockResolvedValueOnce(8); // orCount — con badDomains excluidos

    const [city] = await getCitiesForSelector();
    // Si badDomains se aplica correctamente, el orCount = 8 (no el total sin filtrar)
    expect(city.activityCount).toBe(8);

    // Verificar que activity.count se llamó (strictCount + orCount)
    expect(mocks.mockActivityCount).toHaveBeenCalledTimes(2);
  });

  it('sin fuentes degradadas badDomains es array vacío — no afecta el filtro OR', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG]);
    mocks.mockSourceFindMany.mockResolvedValue([]); // sin bad domains
    mocks.mockActivityCount
      .mockResolvedValueOnce(5)
      .mockResolvedValueOnce(20);

    const [city] = await getCitiesForSelector();
    expect(city.activityCount).toBe(20);
    expect(mocks.mockActivityCount).toHaveBeenCalledTimes(2);
  });
});

// =============================================================================
// Múltiples ciudades — orden preservado
// =============================================================================
describe('getCitiesForSelector — múltiples ciudades', () => {
  beforeEach(() => vi.clearAllMocks());

  it('retorna todas las ciudades con strictCount ≥ 1 en el orden que llegan de BD', async () => {
    mocks.mockCityFindMany.mockResolvedValue([BOG, MED]);
    mocks.mockSourceFindMany.mockResolvedValue([]);
    mocks.mockActivityCount
      .mockResolvedValueOnce(10) // strictCount BOG
      .mockResolvedValueOnce(50) // orCount BOG
      .mockResolvedValueOnce(3)  // strictCount MED
      .mockResolvedValueOnce(12); // orCount MED

    const result = await getCitiesForSelector();
    expect(result).toHaveLength(2);
    expect(result[0].id).toBe('city-bog');
    expect(result[0].activityCount).toBe(50);
    expect(result[1].id).toBe('city-med');
    expect(result[1].activityCount).toBe(12);
  });
});

import { describe, expect, it, vi, beforeEach, afterEach } from 'vitest';
import { quota } from '../quota-tracker';
import { getAvailableKey } from '../quota-tracker';

describe('QuotaTracker', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
    vi.restoreAllMocks();
  });

  it('calcula correctamente el reset para las 08:00 UTC (medianoche PST) si aun no son las 8', async () => {
    // 07:00 UTC (1 hora antes del reset)
    const mockDate = new Date(Date.UTC(2026, 3, 19, 7, 0, 0));
    vi.setSystemTime(mockDate);

    // Mock Redis
    const setMock = vi.fn().mockResolvedValue('OK');
    const getRedisMock = vi.spyOn(quota as any, 'getRedis' as any).mockReturnValue({
      set: setMock,
    } as any);

    await quota.markExhausted('test-key');

    // Expected reset is today at 8:00 UTC
    const expectedReset = new Date(Date.UTC(2026, 3, 19, 8, 0, 0));
    const ttlSeconds = Math.ceil((expectedReset.getTime() - mockDate.getTime()) / 1000);

    expect(setMock).toHaveBeenCalledWith(
      'quota:gemini:test-key',
      expectedReset.toISOString(),
      'EX',
      ttlSeconds
    );
  });

  it('calcula correctamente el reset para el día siguiente si ya pasaron las 8:00 UTC', async () => {
    // 09:00 UTC (1 hora después del reset)
    const mockDate = new Date(Date.UTC(2026, 3, 19, 9, 0, 0));
    vi.setSystemTime(mockDate);

    const setMock = vi.fn().mockResolvedValue('OK');
    const getRedisMock = vi.spyOn(quota as any, 'getRedis' as any).mockReturnValue({
      set: setMock,
    } as any);

    await quota.markExhausted('test-key');

    // Expected reset is TOMORROW at 8:00 UTC
    const expectedReset = new Date(Date.UTC(2026, 3, 20, 8, 0, 0));
    const ttlSeconds = Math.ceil((expectedReset.getTime() - mockDate.getTime()) / 1000);

    expect(setMock).toHaveBeenCalledWith(
      'quota:gemini:test-key',
      expectedReset.toISOString(),
      'EX',
      ttlSeconds
    );
  });

  it('isAvailable limpia la key si el reset ya pasó', async () => {
    const mockDate = new Date(Date.UTC(2026, 3, 19, 10, 0, 0));
    vi.setSystemTime(mockDate);

    const delMock = vi.fn().mockResolvedValue(1);
    
    // Key mock expirada (08:00 UTC del día actual, o sea, hace 2h)
    const getMock = vi.fn().mockResolvedValue(new Date(Date.UTC(2026, 3, 19, 8, 0, 0)).toISOString());
    const getRedisMock = vi.spyOn(quota as any, 'getRedis' as any).mockReturnValue({
      get: getMock,
      del: delMock,
    } as any);

    const available = await quota.isAvailable('test-key');
    expect(available).toBe(true);
    expect(delMock).toHaveBeenCalledWith('quota:gemini:test-key');
  });

  it('getAvailableKey retorna null si todas las llaves están agotadas', async () => {
    process.env.GEMINI_KEYS = 'key1,key2';
    
    // Forzamos isAvailable a false siempre
    vi.spyOn(quota, 'isAvailable').mockResolvedValue(false);

    const key = await getAvailableKey();
    expect(key).toBeNull();
  });

  it('clearAll borra todas las llaves del pool', async () => {
    process.env.GEMINI_KEYS = 'keyA,keyB';
    
    const delMock = vi.fn().mockResolvedValue(1);
    const getRedisMock = vi.spyOn(quota as any, 'getRedis' as any).mockReturnValue({
      del: delMock,
    } as any);

    const cleared = await quota.clearAll();
    
    expect(cleared).toBe(2);
    expect(delMock).toHaveBeenCalledWith('quota:gemini:keyA');
    expect(delMock).toHaveBeenCalledWith('quota:gemini:keyB');
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';

// Mock Prisma first (before importing the module that uses it)
vi.mock('../db', () => ({
  prisma: {
    city: {
      findUnique: vi.fn(),
    },
    scrapingSource: {
      update: vi.fn(),
    },
    $queryRawUnsafe: vi.fn(),
    $executeRawUnsafe: vi.fn(),
  },
}));

vi.mock('../logger', () => ({
  createLogger: () => ({
    info: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
    debug: vi.fn(),
  }),
}));

// Now import the module after mocking its dependencies
import {
  resolvePauseConfig,
  calculateSourceScore,
  pauseSourceIfNeeded,
  unpausSourceIfExpired,
  getSourceDashboardStats,
  GLOBAL_PAUSE_CONFIG,
  CITY_PAUSE_CONFIG,
} from '../source-pause-manager';
import { prisma } from '../db';

describe('source-pause-manager', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('calculateSourceScore', () => {
    it('returns null score if no data', async () => {
      (prisma.$queryRawUnsafe as any).mockResolvedValue([]);

      const score = await calculateSourceScore('source-1');

      expect(score.avgScore).toBeNull();
      expect(score.hasData).toBe(false);
    });

    it('calculates average URL score from logs', async () => {
      (prisma.$queryRawUnsafe as any).mockResolvedValue([
        { avg_score: 55.5, total_urls: 100, low_score_urls: 20 },
      ]);

      const score = await calculateSourceScore('source-1', 'city-1', 1);

      expect(score.avgScore).toBe(55.5);
      expect(score.lowScoreCount).toBe(20);
      expect(score.totalUrls).toBe(100);
      expect(score.hasData).toBe(true);
    });

    it('handles null values gracefully', async () => {
      (prisma.$queryRawUnsafe as any).mockResolvedValue([
        { avg_score: null, total_urls: 0, low_score_urls: 0 },
      ]);

      const score = await calculateSourceScore('source-1');

      expect(score.avgScore).toBeNull();
      expect(score.hasData).toBe(true);
    });
  });

  describe('getSourceDashboardStats', () => {
    it('returns stats with proper SQL LEFT JOINs', async () => {
      const mockStats = [
        {
          id: 'src-1',
          name: 'BibloRed',
          platform: 'WEB',
          city_name: 'Bogotá',
          city_id: 'bogota',
          avg_url_score: 75.5,
          low_score_count: 5,
          high_score_count: 95,
          total_urls_processed: 100,
          last_scan_at: new Date().toISOString(),
          paused_at: null,
          paused_reason: null,
          pause_threshold_score: 20,
          pause_duration_days: 7,
          is_active: true,
        },
      ];

      (prisma.$queryRawUnsafe as any).mockResolvedValue(mockStats);

      const stats = await getSourceDashboardStats('bogota');

      expect(stats).toHaveLength(1);
      expect(stats[0].id).toBe('src-1');
      expect(stats[0].avg_url_score).toBe(75.5);
      expect(stats[0].is_active).toBe(true);
    });
  });

  describe('resolvePauseConfig', () => {
    it('returns global config by default', async () => {
      (prisma.$queryRawUnsafe as any).mockResolvedValue([]); // all queries return empty
      (prisma.city.findUnique as any).mockResolvedValue(null);

      const config = await resolvePauseConfig('source-1');

      expect(config.level).toBe('global');
      expect(config.threshold).toBe(GLOBAL_PAUSE_CONFIG.threshold);
    });

    it('returns source-specific config when available', async () => {
      // When no cityId is passed, resolvePauseConfig skips source_city check and goes straight to source check
      const querySequence = [
        [{ pause_threshold_score: 25, pause_duration_days: 14, auto_pause_enabled: true }], // source config check
      ];
      let callIndex = 0;
      (prisma.$queryRawUnsafe as any).mockImplementation(async () => {
        const result = querySequence[callIndex];
        callIndex++;
        return result;
      });

      const config = await resolvePauseConfig('source-1');

      expect(config.level).toBe('source');
      expect(config.threshold).toBe(25);
    });

    it('respects CITY_PAUSE_CONFIG override', async () => {
      const originalConfig = CITY_PAUSE_CONFIG['bogotá'];
      CITY_PAUSE_CONFIG['bogotá'] = { threshold: 28, durationDays: 21 };

      try {
        (prisma.$queryRawUnsafe as any).mockResolvedValue([]);
        (prisma.city.findUnique as any).mockResolvedValue({
          id: 'bogota-id',
          name: 'Bogotá',
          countryCode: 'CO',
          countryName: 'Colombia',
          timezone: 'America/Bogota',
          currency: 'COP',
          isActive: true,
        });

        const config = await resolvePauseConfig('source-1', 'bogota-id');

        expect(config.level).toBe('city');
        expect(config.threshold).toBe(28);
      } finally {
        if (originalConfig) {
          CITY_PAUSE_CONFIG['bogotá'] = originalConfig;
        } else {
          delete CITY_PAUSE_CONFIG['bogotá'];
        }
      }
    });
  });

  describe('pauseSourceIfNeeded', () => {
    it('does not pause if score is above threshold', async () => {
      const querySequence = [
        [], // source config check (no cityId, so no source_city check)
        [{ avg_score: 50, total_urls: 100, low_score_urls: 10 }], // score calculation
      ];
      let callIndex = 0;
      (prisma.$queryRawUnsafe as any).mockImplementation(async () => {
        const result = querySequence[callIndex];
        callIndex++;
        return result;
      });

      const result = await pauseSourceIfNeeded('source-1');

      expect(result.paused).toBe(false);
      expect(result.reason).toBe('score_above_threshold');
      expect(result.score).toBe(50);
    });

    it('pauses source when score is below threshold', async () => {
      const querySequence = [
        [], // source config check (no cityId, so no source_city check)
        [{ avg_score: 15, total_urls: 100, low_score_urls: 80 }], // score calculation
      ];
      let callIndex = 0;
      (prisma.$queryRawUnsafe as any).mockImplementation(async () => {
        const result = querySequence[callIndex];
        callIndex++;
        return result;
      });
      (prisma.$executeRawUnsafe as any).mockResolvedValue({});
      (prisma.scrapingSource.update as any).mockResolvedValue({});

      const result = await pauseSourceIfNeeded('source-1');

      expect(result.paused).toBe(true);
      expect(result.score).toBe(15);
      expect((prisma.scrapingSource.update as any)).toHaveBeenCalled();
    });

    it('respects auto_pause_enabled flag', async () => {
      (prisma.$queryRawUnsafe as any).mockResolvedValueOnce([
        { pause_threshold_score: 20, pause_duration_days: 7, auto_pause_enabled: false },
      ]); // source config with disabled flag

      const result = await pauseSourceIfNeeded('source-1');

      expect(result.paused).toBe(false);
      expect(result.reason).toBe('auto_pause_disabled');
    });
  });

  describe('unpausSourceIfExpired', () => {
    it('does not unpause if pause period is still active', async () => {
      const now = new Date();
      const pausedAt = new Date(now.getTime() - 1 * 24 * 60 * 60 * 1000); // 1 day ago

      (prisma.$queryRawUnsafe as any).mockResolvedValue([
        { paused_at: pausedAt.toISOString(), pause_duration_days: 7 },
      ]);

      const result = await unpausSourceIfExpired('source-1');

      expect(result.unpaused).toBe(false);
      expect(result.reason).toBe('pause_still_active');
    });

    it('unpauses source when pause period expires', async () => {
      const now = new Date();
      const pausedAt = new Date(now.getTime() - 10 * 24 * 60 * 60 * 1000); // 10 days ago

      (prisma.$queryRawUnsafe as any).mockResolvedValue([
        { paused_at: pausedAt.toISOString(), pause_duration_days: 7 },
      ]);
      (prisma.$executeRawUnsafe as any).mockResolvedValue({});
      (prisma.scrapingSource.update as any).mockResolvedValue({});

      const result = await unpausSourceIfExpired('source-1');

      expect(result.unpaused).toBe(true);
      expect(result.pausedFor).toBe(7);
      expect((prisma.scrapingSource.update as any)).toHaveBeenCalled();
    });

    it('returns not_paused when no pause config exists', async () => {
      (prisma.$queryRawUnsafe as any).mockResolvedValue([]);

      const result = await unpausSourceIfExpired('source-1');

      expect(result.unpaused).toBe(false);
      expect(result.reason).toBe('not_paused');
    });
  });
});

import { redirect } from 'next/navigation'
import { createSupabaseServerClient } from '@/lib/supabase/server'
import { prisma } from '@/lib/db'
import { UserRole } from '@/generated/prisma/client'
import type { User } from '@supabase/supabase-js'

export async function getSession() {
  const supabase = await createSupabaseServerClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()
  return user
}

export async function getSessionWithRole() {
  const supabase = await createSupabaseServerClient()
  const {
    data: { user },
  } = await supabase.auth.getUser()

  if (!user) return null

  // El rol definitivo se lee de app_metadata (seteado por promote-admin script)
  const role = (user.app_metadata?.role as string | undefined) ?? 'parent'

  return { user, role }
}

/**
 * Obtiene o crea el registro del usuario en la tabla `users`.
 * Úsalo en las páginas del perfil en lugar de prisma.user.findUnique.
 */
export async function getOrCreateDbUser(authUser: User) {
  const name =
    authUser.user_metadata?.full_name ??
    authUser.user_metadata?.name ??
    authUser.email?.split('@')[0] ??
    'Usuario'

  const provider = authUser.app_metadata?.provider ?? 'email'

  try {
    return await prisma.user.upsert({
      where: { supabaseAuthId: authUser.id },
      create: {
        supabaseAuthId: authUser.id,
        email: authUser.email ?? null,
        phone: authUser.phone ?? null,
        provider,
        name,
        role: 'PARENT',
      },
      update: {
        provider,
        ...(authUser.email ? { email: authUser.email } : {}),
        ...(authUser.phone ? { phone: authUser.phone } : {}),
      },
    })
  } catch (err: unknown) {
    // Safety net: si hay P2002 por constraints aún no migradas en DB,
    // retornar el usuario existente para no romper el login.
    // Con el schema correcto (sin @unique en phone/email), este bloque nunca debe ejecutarse.
    if ((err as any).code === 'P2002') {
      const existing = await prisma.user.findUnique({
        where: { supabaseAuthId: authUser.id },
      })
      if (existing) return existing
    }
    throw err
  }
}


export async function requireAuth() {
  const user = await getSession()
  if (!user) redirect('/login')
  return user
}

export async function requireRole(roles: UserRole[]) {
  const session = await getSessionWithRole()
  if (!session) redirect('/login')

  const roleMap: Record<string, UserRole> = {
    admin: UserRole.ADMIN,
    moderator: UserRole.MODERATOR,
    provider: UserRole.PROVIDER,
    parent: UserRole.PARENT,
  }

  const userRole = roleMap[session.role] ?? UserRole.PARENT
  if (!roles.includes(userRole)) redirect('/')

  return session
}

// ❗ Nunca usar .toNumber() directamente
export function normalizePrice(value: unknown): number | null {
  let result: number | null = null;

  if (value == null) {
    result = null;
  } else if (typeof value === "number") {
    result = value;
  } else if (typeof value === "string") {
    const parsed = Number(value);
    result = isNaN(parsed) ? null : parsed;
  } else if (typeof value === "object" && value !== null) {
    // Prisma Decimal (toNumber)
    if ("toNumber" in value && typeof (value as any).toNumber === "function") {
      result = (value as any).toNumber();
    } else if ("valueOf" in value && typeof (value as any).valueOf === "function") {
      const val = Number((value as any).valueOf());
      result = isNaN(val) ? null : val;
    }
  }

  if (result === null && process.env.NODE_ENV === "development") {
    console.warn("Invalid price value", value);
  }

  return result;
}

