export type Intent =
  | { type: 'NAVIGATE'; to: string }
  | { type: 'TOGGLE_FAVORITE'; targetId: string; targetType: 'activity' | 'place'; returnTo: string }
  | { type: 'GENERIC_ACTION'; name: string; payload?: any; returnTo?: string }

const STORAGE_KEY = 'hp_intent'
const TTL_MS = 15 * 60 * 1000 // 15 mins

interface StoredIntent {
  intent: Intent
  timestamp: number
}

export const IntentManager = {
  save(intent: Intent): void {
    try {
      const data: StoredIntent = { intent, timestamp: Date.now() }
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data))
    } catch {
      // Ignore silence
    }
  },

  consume(): Intent | null {
    try {
      const raw = localStorage.getItem(STORAGE_KEY)
      if (!raw) return null

      IntentManager.clear()

      const data = JSON.parse(raw) as StoredIntent
      if (!data.intent || !data.timestamp) return null

      // Validate TTL
      if (Date.now() - data.timestamp > TTL_MS) {
        return null
      }

      return data.intent
    } catch {
      return null
    }
  },

  clear(): void {
    try {
      localStorage.removeItem(STORAGE_KEY)
    } catch {
      // Ignore silence
    }
  }
}

// =============================================================================
// logger.ts — Logger estructurado universal
//
// Emite líneas con timestamp + nivel + contexto, capturadas por Vercel Logs.
// En producción: errors se reportan a Sentry si SENTRY_DSN está configurado.
// Compatible con API routes (server) y workers (Node.js process).
// =============================================================================

type Level = 'debug' | 'info' | 'warn' | 'error';

export interface LogMeta {
  ctx?: string;
  error?: unknown;
  [key: string]: unknown;
}

const PREFIXES: Record<Level, string> = {
  debug: 'DEBUG',
  info:  'INFO ',
  warn:  'WARN ',
  error: 'ERROR',
};

// ─── Browser Deduplication (UI Throttle) ──────────────────────────────────────
const recentLogs = new Map<string, number>();
const THROTTLE_MS = 2000;

function isDuplicateBrowserLog(key: string): boolean {
  if (typeof window === 'undefined') return false; // Only deduplicate on client
  const now = Date.now();
  const last = recentLogs.get(key);
  if (last && now - last < THROTTLE_MS) return true;
  
  recentLogs.set(key, now);
  if (recentLogs.size > 200) {
    const threshold = now - THROTTLE_MS;
    for (const [k, v] of recentLogs.entries()) {
      if (v < threshold) recentLogs.delete(k);
    }
  }
  return false;
}

function formatLine(level: Level, message: string, meta?: LogMeta): string {
  const ts  = new Date().toISOString();
  const ctx = meta?.ctx ? `[${meta.ctx}] ` : '';
  // Guard: si meta no es un objeto plano (e.g. se pasó un string o un Error directamente)
  // lo ignoramos para no serializar como array de caracteres {"0":"x","1":"y"...}
  const safeMeta = meta && typeof meta === 'object' && !Array.isArray(meta) ? meta : {};
  // Extra data: todo menos ctx y error (que se loguea por separado)
  const { ctx: _ctx, error: _err, ...rest } = safeMeta;
  const extras = Object.keys(rest).length > 0 ? ` ${JSON.stringify(rest)}` : '';
  return `${ts} ${PREFIXES[level]} ${ctx}${message}${extras}`;
}

function write(level: Level, message: string, meta?: LogMeta): void {
  // 1. Deduplicación en Client-Side (React Strict Mode / Re-renders shielding)
  if (typeof window !== 'undefined') {
    const action = meta?.action ? String(meta.action) : '';
    const result = meta?.result ? String(meta.result) : '';
    const ctxStr = meta?.ctx ? String(meta.ctx) : '';
    const dedupKey = `${level}:${ctxStr}:${message}:${action}:${result}`;
    if (isDuplicateBrowserLog(dedupKey)) return;

    // Producción Frontend limpia: inhibimos logs para no ensuciar consola (salvo hooks de analytics)
    if (process.env.NODE_ENV === 'production') {
      // trackAnalytics(level, message, meta) // Opcional integración
      return; 
    }
  }

  const line = formatLine(level, message, meta);

  if (level === 'error') {
    console.error(line, meta?.error ?? '');
    // Captura asíncrona a Sentry — no bloquea el request
    if (typeof process !== 'undefined' && process.env.SENTRY_DSN && meta?.error) {
      import('@sentry/nextjs')
        .then(({ captureException }) =>
          captureException(meta.error, { extra: { message, ...meta } }),
        )
        .catch(() => { /* fail silently */ });
    }
  } else if (level === 'warn') {
    console.warn(line);
  } else {
    console.log(line);
  }
}

// ── API pública ───────────────────────────────────────────────────────────────

export const logger = {
  debug: (message: string, meta?: LogMeta) => write('debug', message, meta),
  info:  (message: string, meta?: LogMeta) => write('info',  message, meta),
  warn:  (message: string, meta?: LogMeta) => write('warn',  message, meta),
  error: (message: string, meta?: LogMeta) => write('error', message, meta),
};

/**
 * Crea un logger con contexto fijo — evita repetir ctx en cada llamada.
 *
 * @example
 *   const log = createLogger('email');
 *   log.info('Welcome enviado', { to: 'user@example.com' });
 *   // → 2026-03-31T12:00:00Z INFO  [email] Welcome enviado {"to":"user@example.com"}
 */
export function createLogger(ctx: string) {
  return {
    debug: (message: string, meta?: Omit<LogMeta, 'ctx'>) =>
      write('debug', message, { ...meta, ctx }),
    info:  (message: string, meta?: Omit<LogMeta, 'ctx'>) =>
      write('info',  message, { ...meta, ctx }),
    warn:  (message: string, meta?: Omit<LogMeta, 'ctx'>) =>
      write('warn',  message, { ...meta, ctx }),
    error: (message: string, meta?: Omit<LogMeta, 'ctx'>) =>
      write('error', message, { ...meta, ctx }),
  };
}

export type AppLogger = ReturnType<typeof createLogger>;

// =============================================================================
// prisma-serialize.ts — Serialización segura de objetos Prisma
// =============================================================================
//
// PROBLEMA:
//   Prisma devuelve tipos de clase complejos que NO son primitivos JSON:
//     - `Decimal` (decimal.js) → price, latitude, longitude, etc.
//     - `Date`                 → createdAt, startDate, endDate, etc.
//
//   Next.js App Router prohíbe pasar instancias de clases a través de la
//   frontera Server Component → Client Component ("Only plain objects").
//   Intentarlo produce un Fatal Server Error y pantalla negra en producción.
//
// SOLUCIÓN:
//   Usar siempre estas funciones antes de pasar datos de Prisma a cualquier
//   componente con 'use client', ya sea directamente o como prop.
//
// REGLA DE ORO (añadida a CLAUDE.md):
//   "Nunca pases un objeto Prisma directamente a un Client Component.
//    Siempre usa serializeActivity(), serializeLocation() u otro helper
//    tipado de este módulo. En caso de duda, usa toPlainObject()."
//
// =============================================================================

// ─── Primitivos ───────────────────────────────────────────────────────────────

/**
 * Convierte un Decimal de Prisma (decimal.js) a number.
 * Funciona con: Decimal.js | string numérica | number nativo | null | undefined
 */
export function toNumber(value: unknown): number | null {
  if (value === null || value === undefined) return null;
  if (typeof value === 'number') return value;
  if (typeof value === 'string') {
    const n = parseFloat(value);
    return isNaN(n) ? null : n;
  }
  // Decimal.js instance (Prisma Decimal)
  if (typeof (value as any).toNumber === 'function') {
    return (value as any).toNumber();
  }
  return null;
}

/**
 * Convierte un Date de Prisma a ISO string serializable.
 * Los strings ya en formato ISO pasan sin transformación.
 */
export function toISOString(value: Date | string | null | undefined): string | null {
  if (!value) return null;
  if (value instanceof Date) return value.toISOString();
  return value; // ya es string ISO
}

// ─── DTOs — Plain object types para pasar a Client Components ─────────────────

/**
 * Representación serializable de una Activity de Prisma.
 * Todos los campos son primitivos JSON-seguros (sin Decimal ni Date).
 */
export interface SerializedActivity {
  id: string;
  title: string;
  description: string;
  type: string;
  status: string;
  audience: string;
  ageMin: number | null;
  ageMax: number | null;
  /** Convertido de Decimal a number */
  price: number | null;
  priceCurrency: string;
  pricePeriod: string | null;
  imageUrl: string | null;
  sourceUrl: string | null;
  sourceDomain: string | null;
  duplicatesCount: number;
  /** Convertido de Date a ISO string */
  createdAt: string;
  provider: {
    name: string;
    isVerified: boolean;
    isPremium: boolean;
  } | null;
  location: {
    name: string;
    neighborhood: string | null;
    city: { name: string } | null;
  } | null;
  categories: {
    category: { id: string; name: string; slug: string };
  }[];
  _count: { views: number };
}

/**
 * Representación serializable de una Location de Prisma.
 * Excluye latitude y longitude (Decimal) que nunca necesitan pasar al cliente.
 */
export interface SerializedLocation {
  id: string;
  name: string;
  address: string;
  neighborhood: string | null;
  city: { name: string } | null;
}

// ─── Serializers ──────────────────────────────────────────────────────────────

/**
 * Serializa una Activity de Prisma a un objeto plano apto para Client Components.
 *
 * @example
 * // En un Server Component:
 * const activity = await prisma.activity.findUnique({ ... })
 * return <ActivityCard activity={serializeActivity(activity)} />
 */
export function serializeActivity(act: any): SerializedActivity {
  return {
    id: act.id,
    title: act.title,
    description: act.description ?? '',
    type: act.type,
    status: act.status,
    audience: act.audience,
    ageMin: act.ageMin ?? null,
    ageMax: act.ageMax ?? null,
    price: toNumber(act.price),
    priceCurrency: act.priceCurrency ?? 'COP',
    pricePeriod: act.pricePeriod ?? null,
    imageUrl: act.imageUrl ?? null,
    sourceUrl: act.sourceUrl ?? null,
    sourceDomain: act.sourceDomain ?? null,
    duplicatesCount: act.duplicatesCount ?? 0,
    createdAt: toISOString(act.createdAt) ?? new Date().toISOString(),
    provider: act.provider
      ? {
          name: act.provider.name,
          isVerified: act.provider.isVerified ?? false,
          isPremium: act.provider.isPremium ?? false,
        }
      : null,
    location: act.location
      ? {
          name: act.location.name,
          neighborhood: act.location.neighborhood ?? null,
          city: act.location.city ? { name: act.location.city.name } : null,
        }
      : null,
    categories: (act.categories ?? []).map((c: any) => ({
      category: {
        id: c.category.id,
        name: c.category.name,
        slug: c.category.slug,
      },
    })),
    _count: { views: act._count?.views ?? 0 },
  };
}

/**
 * Serializa una Location de Prisma a un objeto plano apto para Client Components.
 * No incluye latitude/longitude (Decimal) que nunca se necesitan en el frontend.
 */
export function serializeLocation(loc: any): SerializedLocation {
  return {
    id: loc.id,
    name: loc.name,
    address: loc.address ?? '',
    neighborhood: loc.neighborhood ?? null,
    city: loc.city ? { name: loc.city.name } : null,
  };
}

/**
 * Escape hatch genérico: convierte CUALQUIER objeto Prisma a plain object.
 * Usa esto cuando no existe un serializer específico para el tipo.
 *
 * ADVERTENCIA: Es menos eficiente que los serializers tipados porque hace
 * un round-trip JSON completo. Úsalo solo para tipos sin serializer propio.
 * No uses esto para Activity o Location — usa serializeActivity/serializeLocation.
 */
export function toPlainObject<T>(value: T): T {
  return JSON.parse(JSON.stringify(value));
}

// source-pause-manager.ts
// Gestiona la pausa automática de fuentes según URL score
// Configurable por: general (default), ciudad, fuente específica

import { prisma } from './db';
import { createLogger } from './logger';

const log = createLogger('source-pause-manager');

/**
 * Configuración global de pause (fallback)
 * IMPORTANTE: These can be overridden per city or per source
 */
export const GLOBAL_PAUSE_CONFIG = {
  threshold: 20, // score < 20 → pausar
  durationDays: 7, // duración del pause
  enabled: true,
};

/**
 * Configuración por ciudad (overrides global)
 * Las claves deben ser nombres de ciudad en minúsculas
 */
export const CITY_PAUSE_CONFIG: Record<string, { threshold?: number; durationDays?: number; enabled?: boolean }> = {
  // Ejemplos:
  // 'bogotá': { threshold: 25, durationDays: 14 },
  // 'medellín': { threshold: 15, durationDays: 5 },
};

/**
 * Resolva la configuración de pause aplicable a una fuente
 * Priority: SourceSpecific > City > Global
 */
export async function resolvePauseConfig(sourceId: string, cityId?: string) {
  // 1. Buscar config específica de fuente + ciudad
  if (cityId && sourceId) {
    const sourceConfig = await prisma.$queryRawUnsafe<any[]>(
      `SELECT pause_threshold_score, pause_duration_days, auto_pause_enabled
       FROM source_pause_config
       WHERE source_id = $1 AND city_id = $2
       LIMIT 1`,
      sourceId,
      cityId,
    );
    if (sourceConfig && sourceConfig.length > 0) {
      return {
        threshold: sourceConfig[0].pause_threshold_score,
        durationDays: sourceConfig[0].pause_duration_days,
        enabled: sourceConfig[0].auto_pause_enabled,
        level: 'source_city',
      };
    }
  }

  // 2. Buscar config específica de fuente (sin city)
  if (sourceId) {
    const sourceConfig = await prisma.$queryRawUnsafe<any[]>(
      `SELECT pause_threshold_score, pause_duration_days, auto_pause_enabled
       FROM source_pause_config
       WHERE source_id = $1 AND city_id IS NULL
       LIMIT 1`,
      sourceId,
    );
    if (sourceConfig && sourceConfig.length > 0) {
      return {
        threshold: sourceConfig[0].pause_threshold_score,
        durationDays: sourceConfig[0].pause_duration_days,
        enabled: sourceConfig[0].auto_pause_enabled,
        level: 'source',
      };
    }
  }

  // 3. Buscar config por ciudad
  if (cityId) {
    const city = await prisma.city.findUnique({ where: { id: cityId } });
    if (city && CITY_PAUSE_CONFIG[city.name.toLowerCase()]) {
      const cityConfig = CITY_PAUSE_CONFIG[city.name.toLowerCase()];
      return {
        threshold: cityConfig.threshold ?? GLOBAL_PAUSE_CONFIG.threshold,
        durationDays: cityConfig.durationDays ?? GLOBAL_PAUSE_CONFIG.durationDays,
        enabled: cityConfig.enabled ?? GLOBAL_PAUSE_CONFIG.enabled,
        level: 'city',
      };
    }
  }

  // 4. Fallback a config global
  return {
    threshold: GLOBAL_PAUSE_CONFIG.threshold,
    durationDays: GLOBAL_PAUSE_CONFIG.durationDays,
    enabled: GLOBAL_PAUSE_CONFIG.enabled,
    level: 'global',
  };
}

/**
 * Calcula el score agregado de URLs para una fuente
 * Basado en últimos logs de scraping
 */
export async function calculateSourceScore(sourceId: string, cityId?: string, weeksBack = 1) {
  const sinceDatetime = new Date(Date.now() - weeksBack * 7 * 24 * 60 * 60 * 1000);

  // Obtener logs recientes
  const logs = await prisma.$queryRawUnsafe<
    Array<{ avg_score: number | null; total_urls: number; low_score_urls: number }>
  >(
    `
    SELECT
      AVG(CAST(metadata->>'avg_url_score' AS FLOAT)) as avg_score,
      COUNT(DISTINCT id) as total_urls,
      COUNT(CASE WHEN CAST(metadata->>'avg_url_score' AS FLOAT) < 45 THEN 1 END) as low_score_urls
    FROM scraping_log
    WHERE source_id = $1
      AND city_id = $2
      AND started_at >= $3
      AND status IN ('SUCCESS', 'PARTIAL')
  `,
    sourceId,
    cityId,
    sinceDatetime,
  );

  if (!logs || logs.length === 0) {
    return { avgScore: null, lowScoreCount: 0, totalUrls: 0, hasData: false };
  }

  const log_data = logs[0];
  return {
    avgScore: log_data.avg_score ? Math.round(parseFloat(String(log_data.avg_score)) * 10) / 10 : null,
    lowScoreCount: Number(log_data.low_score_urls || 0),
    totalUrls: Number(log_data.total_urls || 0),
    hasData: true,
  };
}

/**
 * Pausa una fuente automáticamente si score < threshold
 */
export async function pauseSourceIfNeeded(sourceId: string, cityId?: string) {
  const config = await resolvePauseConfig(sourceId, cityId);

  if (!config.enabled) {
    log.info(`Auto-pause disabled for source ${sourceId} at level: ${config.level}`);
    return { paused: false, reason: 'auto_pause_disabled' };
  }

  const score = await calculateSourceScore(sourceId, cityId, 1);

  if (!score.hasData) {
    log.warn(`No data available to calculate score for source ${sourceId}`);
    return { paused: false, reason: 'no_data', score: score.avgScore };
  }

  if (score.avgScore === null || score.avgScore >= config.threshold) {
    log.info(`Source ${sourceId} score ${score.avgScore} >= threshold ${config.threshold} — no action`);
    return { paused: false, reason: 'score_above_threshold', score: score.avgScore };
  }

  // Score está por debajo del threshold — pausar
  const reason = `Auto-paused: URL score ${score.avgScore} < ${config.threshold} (config level: ${config.level})`;
  const pauseUntil = new Date(Date.now() + config.durationDays * 24 * 60 * 60 * 1000);

  // Actualizar config de pause
  if (cityId) {
    await prisma.$executeRawUnsafe(
      `
      INSERT INTO source_pause_config (source_id, city_id, pause_threshold_score, pause_duration_days, paused_at, paused_reason)
      VALUES ($1, $2, $3, $4, NOW(), $5)
      ON CONFLICT (source_id, city_id) DO UPDATE SET
        paused_at = NOW(),
        paused_reason = $5,
        updated_at = NOW()
      `,
      sourceId,
      cityId,
      config.threshold,
      config.durationDays,
      reason,
    );
  } else {
    await prisma.$executeRawUnsafe(
      `
      INSERT INTO source_pause_config (source_id, city_id, pause_threshold_score, pause_duration_days, paused_at, paused_reason)
      VALUES ($1, NULL, $2, $3, NOW(), $4)
      ON CONFLICT (source_id, city_id) DO UPDATE SET
        paused_at = NOW(),
        paused_reason = $4,
        updated_at = NOW()
      `,
      sourceId,
      config.threshold,
      config.durationDays,
      reason,
    );
  }

  // Actualizar isActive en ScrapingSource
  await prisma.scrapingSource.update({
    where: { id: sourceId },
    data: { isActive: false },
  });

  log.info(`✅ Source ${sourceId} paused until ${pauseUntil.toISOString()}: ${reason}`);
  return { paused: true, pauseUntil, score: score.avgScore, reason };
}

/**
 * Despausa fuentes automáticamente si período ya expiró
 */
export async function unpausSourceIfExpired(sourceId: string, cityId?: string) {
  const pauseConfig = await prisma.$queryRawUnsafe<any[]>(
    `
    SELECT paused_at, pause_duration_days
    FROM source_pause_config
    WHERE source_id = $1 AND city_id = $2
    `,
    sourceId,
    cityId || null,
  );

  if (!pauseConfig || pauseConfig.length === 0 || !pauseConfig[0].paused_at) {
    return { unpaused: false, reason: 'not_paused' };
  }

  const config = pauseConfig[0];
  const pausedAt = new Date(config.paused_at);
  const expireAt = new Date(pausedAt.getTime() + config.pause_duration_days * 24 * 60 * 60 * 1000);
  const now = new Date();

  if (now < expireAt) {
    return { unpaused: false, reason: 'pause_still_active', expireAt };
  }

  // Despausa
  if (cityId) {
    await prisma.$executeRawUnsafe(
      `
      UPDATE source_pause_config
      SET paused_at = NULL, paused_reason = NULL, updated_at = NOW()
      WHERE source_id = $1 AND city_id = $2
      `,
      sourceId,
      cityId,
    );
  } else {
    await prisma.$executeRawUnsafe(
      `
      UPDATE source_pause_config
      SET paused_at = NULL, paused_reason = NULL, updated_at = NOW()
      WHERE source_id = $1 AND city_id IS NULL
      `,
      sourceId,
    );
  }

  // Reactivar en ScrapingSource (si no hay otros motivos de pausa)
  await prisma.scrapingSource.update({
    where: { id: sourceId },
    data: { isActive: true },
  });

  log.info(`✅ Source ${sourceId} unpaused after ${config.pause_duration_days} days`);
  return { unpaused: true, pausedFor: config.pause_duration_days, score: null };
}

/**
 * Obtener dashboard stats de todas las fuentes
 */
export async function getSourceDashboardStats(cityId?: string) {
  let query = `
    SELECT
      s.id,
      s.name,
      s.platform,
      c.name as city_name,
      c.id as city_id,
      sus.avg_url_score,
      sus.low_score_count,
      sus.high_score_count,
      sus.total_urls_processed,
      sus.last_scan_at,
      spc.paused_at,
      spc.paused_reason,
      spc.pause_threshold_score,
      spc.pause_duration_days,
      s.is_active
    FROM scraping_source s
    LEFT JOIN city c ON s.city_id = c.id
    LEFT JOIN source_url_stats sus ON s.id = sus.source_id AND (sus.city_id = c.id OR sus.city_id IS NULL)
    LEFT JOIN source_pause_config spc ON s.id = spc.source_id AND (spc.city_id = c.id OR spc.city_id IS NULL)
    WHERE 1=1
  `;

  const params: any[] = [];
  if (cityId) {
    query += ` AND c.id = $1`;
    params.push(cityId);
  }

  query += ` ORDER BY s.name`;

  const stats = await prisma.$queryRawUnsafe<any[]>(query, ...params);
  return stats;
}

import { describe, it, expect, vi, beforeEach } from 'vitest';

const {
