import { updateSession } from '../middleware';
import { NextResponse } from 'next/server';

describe('updateSession', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockGetUser.mockResolvedValue({ data: { user: null } });
  });

  it('crea supabase server client con cookie handlers', async () => {
    const mockRequest = {
      cookies: { getAll: mockCookiesGetAll, set: mockCookiesSet },
    } as any;

    await updateSession(mockRequest);

    expect(mockCreateServerClient).toHaveBeenCalledWith(
      process.env.NEXT_PUBLIC_SUPABASE_URL,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
      expect.objectContaining({
        cookies: expect.objectContaining({
          getAll: expect.any(Function),
          setAll: expect.any(Function),
        }),
      }),
    );
  });

  it('retorna user y supabaseResponse', async () => {
    const mockUser = { id: 'user-1', email: 'test@test.com' };
    mockGetUser.mockResolvedValue({ data: { user: mockUser } });

    const mockRequest = {
      cookies: { getAll: mockCookiesGetAll, set: mockCookiesSet },
    } as any;

    const result = await updateSession(mockRequest);
    expect(result.user).toEqual(mockUser);
    expect(result.supabaseResponse).toBeDefined();
  });

  it('retorna user null si no hay sesión', async () => {
    mockGetUser.mockResolvedValue({ data: { user: null } });

    const mockRequest = {
      cookies: { getAll: mockCookiesGetAll, set: mockCookiesSet },
    } as any;

    const result = await updateSession(mockRequest);
    expect(result.user).toBeNull();
  });

  it('cookies.getAll delega a request.cookies.getAll', async () => {
    const mockRequest = {
      cookies: { getAll: mockCookiesGetAll, set: mockCookiesSet },
    } as any;

    await updateSession(mockRequest);

    const cookiesConfig = (mockCreateServerClient.mock.calls as any)[0][2].cookies;
    cookiesConfig.getAll();
    expect(mockCookiesGetAll).toHaveBeenCalled();
  });

  it('cookies.setAll actualiza request y response cookies', async () => {
    const mockRequest = {
      cookies: { getAll: mockCookiesGetAll, set: mockCookiesSet },
    } as any;

    await updateSession(mockRequest);

    const cookiesConfig = (mockCreateServerClient.mock.calls as any)[0][2].cookies;
    cookiesConfig.setAll([
      { name: 'token', value: 'v1', options: { path: '/' } },
    ]);

    expect(mockCookiesSet).toHaveBeenCalledWith('token', 'v1');
    expect(NextResponse.next).toHaveBeenCalled();
    expect(mockResponseCookiesSet).toHaveBeenCalledWith('token', 'v1', { path: '/' });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';

const { mockCreateServerClient, mockCookieStore } = vi.hoisted(() => {
  const mockCookieStore = {
    getAll: vi.fn(() => [{ name: 'sb-token', value: 'abc' }]),
    set: vi.fn(),
  };
  const mockSupabaseClient = { auth: { getUser: vi.fn() } };
  const mockCreateServerClient = vi.fn(() => mockSupabaseClient);
  return { mockCreateServerClient, mockCookieStore, mockSupabaseClient };
});

vi.mock('@supabase/ssr', () => ({
  createServerClient: mockCreateServerClient,
}));

vi.mock('next/headers', () => ({
  cookies: vi.fn(async () => mockCookieStore),
}));

import { createSupabaseServerClient } from '../server';

describe('createSupabaseServerClient', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockCookieStore.getAll.mockReturnValue([{ name: 'sb-token', value: 'abc' }]);
    mockCookieStore.set.mockImplementation(() => {});
  });

  it('crea server client con las variables de entorno correctas', async () => {
    const client = await createSupabaseServerClient();

    expect(mockCreateServerClient).toHaveBeenCalledWith(
      process.env.NEXT_PUBLIC_SUPABASE_URL,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
      expect.objectContaining({
        cookies: expect.objectContaining({
          getAll: expect.any(Function),
          setAll: expect.any(Function),
        }),
      }),
    );
    expect(client).toBeDefined();
  });

  it('cookies.getAll() delega al cookieStore', async () => {
    await createSupabaseServerClient();

    const cookiesConfig = (mockCreateServerClient.mock.calls as any)[0][2].cookies;
    const result = cookiesConfig.getAll();
    expect(result).toEqual([{ name: 'sb-token', value: 'abc' }]);
  });

  it('cookies.setAll() llama cookieStore.set para cada cookie', async () => {
    await createSupabaseServerClient();

    const cookiesConfig = (mockCreateServerClient.mock.calls as any)[0][2].cookies;
    const cookiesToSet = [
      { name: 'token', value: 'val1', options: { path: '/' } },
      { name: 'refresh', value: 'val2', options: { path: '/' } },
    ];
    cookiesConfig.setAll(cookiesToSet);
    expect(mockCookieStore.set).toHaveBeenCalledTimes(2);
    expect(mockCookieStore.set).toHaveBeenCalledWith('token', 'val1', { path: '/' });
  });

  it('cookies.setAll() no lanza error si cookieStore.set falla (Server Component)', async () => {
    mockCookieStore.set.mockImplementation(() => {
      throw new Error('Cannot set cookies in Server Component');
    });

    await createSupabaseServerClient();

    const cookiesConfig = (mockCreateServerClient.mock.calls as any)[0][2].cookies;
    expect(() => {
      cookiesConfig.setAll([{ name: 'x', value: 'y', options: {} }]);
    }).not.toThrow();
  });
});

// In-memory Anti-Spam (Throttle) temporal cache
const lastEventMap = new Map<string, number>();

function shouldTrack(key: string, delay: number) {
  const now = Date.now();
  const last = lastEventMap.get(key);

  if (last && now - last < delay) {
    return false;
  }

  // Update in throttle registry
  lastEventMap.set(key, now);
  
  // Limpiar llaves residuales para evitar Mem-leak si la sesion es muy prolongada (opcional pero util en SPA)
  if (lastEventMap.size > 500) lastEventMap.clear();

  return true;
}

export async function trackEvent({
  type,
  activityId,
  path,
  metadata
}: {
  type: string;
  activityId?: string;
  path?: string;
  metadata?: Record<string, unknown>;
}) {
  try {
    let delay = 0;

    if (type === "activity_click") delay = 500;
    if (type === "outbound_click") delay = 1000;

    const key = `${type}:${activityId || path || "global"}`;

    if (delay > 0 && !shouldTrack(key, delay)) {
      return; // Bloqueo temporal Anti-Spam Throttled
    }

    await fetch("/api/events", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      // Habilitar keepalive para asegurar envio al cambiar de ruta
      keepalive: true, 
      body: JSON.stringify({
        type,
        activityId,
        path,
        metadata
      })
    });

  } catch (e) {
    // fail silently para no afectar performance UX ni crashear arbol de render...
    // console.warn('Silenced Event Error');
  }
}

