      ...actividadNLPBase,
      minAge: undefined,
    };

    await storage.saveActivity(dataConEdadUndefined, 'https://ejemplo.com/edadundefined');

    const d = mocks.mockActivityCreate.mock.calls[0]?.[0]?.data;
    expect(d.ageMin).toBeNull();
  });

  it('startDate es null cuando schedules existe pero schedules[0].startDate es undefined', async () => {
    const dataConSchedulesSinFechas: ActivityNLPResult = {
      ...actividadNLPBase,
      schedules: [{ startDate: undefined as any, endDate: undefined as any, notes: undefined }],
    };

    const result = await storage.saveActivity(dataConSchedulesSinFechas, 'https://ejemplo.com/sinfechas');

    expect(result.id).toBe('act-001');
    const d = mocks.mockActivityCreate.mock.calls[0]?.[0]?.data;
    expect(d.startDate).toBeNull();
    expect(d.endDate).toBeNull();
  });

  it('audience null se mapea a ALL (branch null del operador ??)', async () => {
    const dataAudienceNull: ActivityNLPResult = {
      ...actividadNLPBase,
      audience: null as any,
    };

    await storage.saveActivity(dataAudienceNull, 'https://ejemplo.com/audiencenull');

    const d = mocks.mockActivityCreate.mock.calls[0]?.[0]?.data;
    expect(d.audience).toBe('ALL');
  });
});

import { describe, it, expect } from 'vitest';
import { activityNLPResultSchema, discoveredActivityUrlsSchema } from '../types';

describe('activityNLPResultSchema', () => {
  const actividadValida = {
    title: 'Taller de pintura para niños',
    description: 'Aprende técnicas básicas de pintura',
    categories: ['Arte y Creatividad'],
    minAge: 5,
    maxAge: 12,
    price: 0,
    pricePeriod: 'FREE' as const,
    currency: 'COP',
    confidenceScore: 0.95,
  };

  it('valida una actividad correcta', () => {
    const result = activityNLPResultSchema.safeParse(actividadValida);
    expect(result.success).toBe(true);
  });

  it('falla si falta el título (undefined)', () => {
    const { title, ...sinTitulo } = actividadValida;
    expect(activityNLPResultSchema.safeParse(sinTitulo).success).toBe(false);
  });

  it('normaliza title vacío a "Sin título" (tolerancia Gemini)', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, title: '' });
    expect(result.success).toBe(true);
    if (result.success) expect(result.data.title).toBe('Sin título');
  });

  it('normaliza title null a "Sin título" (tolerancia Gemini)', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, title: null });
    expect(result.success).toBe(true);
    if (result.success) expect(result.data.title).toBe('Sin título');
  });

  it('normaliza categories vacío a ["General"] (tolerancia Gemini)', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, categories: [] });
    expect(result.success).toBe(true);
    if (result.success) expect(result.data.categories).toEqual(['General']);
  });

  it('normaliza categories null a ["General"] (tolerancia Gemini)', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, categories: null });
    expect(result.success).toBe(true);
    if (result.success) expect(result.data.categories).toEqual(['General']);
  });

  it('falla si confidenceScore > 1', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, confidenceScore: 1.5 });
    expect(result.success).toBe(false);
  });

  it('falla si confidenceScore < 0', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, confidenceScore: -0.1 });
    expect(result.success).toBe(false);
  });

  it('acepta null en description (.nullable lo permite; .default solo aplica a undefined)', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, description: null });
    expect(result.success).toBe(true);
    if (result.success) expect(result.data.description).toBeNull();
  });

  it('convierte null a undefined en campos opcionales de string', () => {
    const conLocation = {
      ...actividadValida,
      location: { address: null, city: 'Bogotá' },
    };
    const result = activityNLPResultSchema.safeParse(conLocation);
    expect(result.success).toBe(true);
    if (result.success) expect(result.data.location?.address).toBeUndefined();
  });

  it('falla si currency no tiene exactamente 3 caracteres', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, currency: 'DOLAR' });
    expect(result.success).toBe(false);
  });

  it('falla si pricePeriod no es un valor válido', () => {
    const result = activityNLPResultSchema.safeParse({ ...actividadValida, pricePeriod: 'ANUAL' });
    expect(result.success).toBe(false);
  });

  it('valida los 4 valores de pricePeriod', () => {
    const periodos = ['PER_SESSION', 'MONTHLY', 'TOTAL', 'FREE'] as const;
    for (const periodo of periodos) {
      const result = activityNLPResultSchema.safeParse({ ...actividadValida, pricePeriod: periodo });
      expect(result.success).toBe(true);
    }
  });
});

describe('discoveredActivityUrlsSchema', () => {
  it('valida array de índices', () => {
    const result = discoveredActivityUrlsSchema.safeParse({
      indices: [1, 3, 7],
    });
    expect(result.success).toBe(true);
  });

  it('acepta array vacío', () => {
    const result = discoveredActivityUrlsSchema.safeParse({ indices: [] });
    expect(result.success).toBe(true);
  });

  it('falla si falta indices', () => {
    const result = discoveredActivityUrlsSchema.safeParse({});
    expect(result.success).toBe(false);
  });
});

import { getErrorMessage } from '../../lib/error';
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { PrismaPg } from '@prisma/adapter-pg';
import { PrismaClient } from '../../generated/prisma/client';
import { createLogger } from '../../lib/logger';

const log = createLogger('scraping:cache');

type CacheEntry = {
  url: string;
  title: string;
  scrapedAt: string;
  /** Último <lastmod> visto en el sitemap cuando se scrapeó esta URL. */
  lastmod?: string;
  /** Origen del parser que extrajo esta URL. */
  parserSource?: 'gemini' | 'fallback';
  /** Confidence score obtenida en la última extracción. */
  confidenceScore?: number;
  /**
   * true  → se procesó con fallback Cheerio y no se guardó (confidence < 0.5).
   *         Debe re-procesarse con Gemini en el próximo run que tenga cuota.
   * false → ya procesado con Gemini, o guardado correctamente.
   */
  needsReparse?: boolean;
};

type CacheData = {
  entries: Record<string, CacheEntry>;
};

const CACHE_PATH = 'data/scraping-cache.json';

/**
 * ScrapingCache — caché dual: disco (local, rápido) + BD (persistente entre máquinas).
 *
 * Estrategia:
 * - Al iniciar: carga desde disco (sync, instantáneo)
 * - syncFromDb(): carga desde BD y fusiona con disco (call explícito antes de correr)
 * - save(): guarda en disco
 * - saveToDb(): persiste entradas nuevas en BD (call explícito al final)
 */
export class ScrapingCache {
  private data: CacheData;
  private newEntries: Map<string, { title: string; source: string }> = new Map();
  private sourceName: string;

  constructor(sourceName = 'unknown') {
    this.sourceName = sourceName;
    this.data = this.load();
  }

  private load(): CacheData {
    if (!existsSync(CACHE_PATH)) return { entries: {} };
    try {
      return JSON.parse(readFileSync(CACHE_PATH, 'utf-8'));
    } catch {
      return { entries: {} };
    }
  }

  /** Sincroniza desde BD — llamar antes de procesar para evitar re-scrapear */
  async syncFromDb(source?: string): Promise<void> {
    try {
      const adapter = new PrismaPg({ connectionString: process.env.DATABASE_URL! });
      const prisma = new PrismaClient({ adapter });

      const where = source ? { source } : {};
      const rows = await (prisma as any).scrapingCache.findMany({ where, select: { url: true, title: true, scrapedAt: true } });
      let added = 0;
      for (const row of rows) {
        if (!(row.url in this.data.entries)) {
          this.data.entries[row.url] = { url: row.url, title: row.title, scrapedAt: row.scrapedAt.toISOString() };
          added++;
        }
      }
      await prisma.$disconnect();
      if (added > 0) log.info(`syncFromDb: ${added} entradas nuevas desde BD (total: ${this.size})`);
    } catch (err: unknown) {
      log.warn(`syncFromDb falló (non-fatal, usando solo disco): ${getErrorMessage(err) ?? String(err)}`);
    }
  }

  /** Persiste entradas nuevas en BD */
  async saveToDb(): Promise<void> {
    if (this.newEntries.size === 0) return;
    try {
      const adapter = new PrismaPg({ connectionString: process.env.DATABASE_URL! });
      const prisma = new PrismaClient({ adapter });

      const data = Array.from(this.newEntries.entries()).map(([url, { title, source }]) => ({
        url,
        title: title.slice(0, 499),
        source,
      }));

      // upsert en batch
      for (const entry of data) {
        await (prisma as any).scrapingCache.upsert({
          where: { url: entry.url },
          create: entry,
          update: { title: entry.title, source: entry.source },
        });
      }

      await prisma.$disconnect();
      log.info(`saveToDb: ${data.length} entradas guardadas en BD`);
      this.newEntries.clear();
    } catch (err: unknown) {
      log.warn(`saveToDb falló (non-fatal): ${getErrorMessage(err) ?? String(err)}`);
    }
  }

  save(): void {
    writeFileSync(CACHE_PATH, JSON.stringify(this.data, null, 2));
  }

  /** Actualiza el nombre de fuente (se llama cuando se conoce la URL del listado). */
  setSource(name: string): void {
    this.sourceName = name;
  }

  has(url: string): boolean {
    return url in this.data.entries;
  }

  /**
   * Registra una URL como procesada.
   * @param meta.parserSource  'gemini' | 'fallback' — quién extrajo el contenido
   * @param meta.confidenceScore — score de la extracción
   * Si parserSource='fallback' y confidenceScore < 0.5, marca needsReparse=true
   * para que el próximo run con Gemini disponible la re-procese.
   */
  add(url: string, title: string, lastmod?: string, meta?: {
    parserSource?: 'gemini' | 'fallback';
    confidenceScore?: number;
  }): void {
    const parserSource   = meta?.parserSource;
    const confidenceScore = meta?.confidenceScore;
    const needsReparse   = parserSource === 'fallback'
      && confidenceScore !== undefined
      && confidenceScore < 0.5;

    this.data.entries[url] = {
      url,
      title,
      scrapedAt: new Date().toISOString(),
      lastmod,
      parserSource,
      confidenceScore,
      needsReparse: needsReparse || false,
    };
    this.newEntries.set(url, { title, source: this.sourceName });
  }

  /** true si la URL fue cacheada con fallback de baja confianza y debe re-procesarse con Gemini. */
  isMarkedForReparse(url: string): boolean {
    return this.data.entries[url]?.needsReparse === true;
  }

  /** Devuelve el subconjunto de `candidates` que están marcados para re-proceso. */
  getReparseUrls(candidates: string[]): string[] {
    return candidates.filter((url) => this.isMarkedForReparse(url));
  }

  /**
   * Obtiene TODAS las URLs guardadas localmente en cache que necesitan reparse para un domino específico.
   * Útil para el Recovery Pipeline del Scheduler Inteligente.
   */
  getReparseUrlsByDomain(domain: string): string[] {
    const urls: string[] = [];
    for (const entry of Object.values(this.data.entries)) {
      if (entry.needsReparse === true && entry.url.includes(domain)) {
        urls.push(entry.url);
      }
    }
    return urls;
  }

  filterNew(urls: string[]): string[] {
    return urls.filter((url) => !this.has(url));
  }

  /**
   * SPI — Sitemap Pre-Index filter.
   *
   * Evita descargar páginas que no han cambiado desde el último scrape.
   * Lógica por URL:
   *   - No en cache            → incluir (primera vez)
   *   - En cache, sin lastmod  → skip (comportamiento conservador)
   *   - En cache, lastmod > scrapedAt → incluir (página actualizada)
   *   - En cache, lastmod ≤ scrapedAt → skip (sin cambios confirmados)
   *
   * @returns urls  — array de URLs a procesar
   * @returns spiSkipped — cuántas se saltaron por lastmod
   */
  filterSPI(entries: Array<{ url: string; lastmod?: string }>): { urls: string[]; spiSkipped: number } {
    const urls: string[] = [];
    let spiSkipped = 0;

    for (const entry of entries) {
      const cached = this.data.entries[entry.url];

      if (!cached) {
        // URL nueva — nunca procesada
        urls.push(entry.url);
        continue;
      }

      if (!entry.lastmod) {
        // Sin información de lastmod → comportamiento conservador: skip
        spiSkipped++;
        continue;
      }

      const lastmodMs  = new Date(entry.lastmod).getTime();
      const scrapedMs  = new Date(cached.scrapedAt).getTime();

      if (isNaN(lastmodMs)) {
        // lastmod inválido → skip conservador
        spiSkipped++;
        continue;
      }

      if (lastmodMs > scrapedMs) {
        // Página modificada después de nuestro último scrape → re-fetch
        urls.push(entry.url);
      } else {
        // Sin cambios
        spiSkipped++;
      }
    }

    return { urls, spiSkipped };
  }

  get size(): number {
    return Object.keys(this.data.entries).length;
  }
}

import { getErrorMessage } from '../../../lib/error';
import * as cheerio from 'cheerio';
import { Agent } from 'undici';
import { Extractor, ScrapedRawData, DiscoveredLink } from '../types';
import { createLogger } from '../../../lib/logger';

const log = createLogger('scraping:cheerio');

// Algunos sitios .gov.co tienen cadena SSL incompleta (UNABLE_TO_VERIFY_LEAF_SIGNATURE).
// Node.js 24 (undici) los rechaza. Para dominios conocidos usamos dispatcher relajado.
const RELAXED_TLS_DOMAINS = ['jbb.gov.co', 'cinematecadebogota.gov.co', 'planetariodebogota.gov.co'];
const relaxedDispatcher = new Agent({ connect: { rejectUnauthorized: false } });

function fetchOptions(url: string): RequestInit {
  try {
    const host = new URL(url).hostname;
    if (RELAXED_TLS_DOMAINS.some((d) => host.endsWith(d))) {
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-ignore — dispatcher es undici (Node.js 18+), no está en tipos DOM fetch
      return { dispatcher: relaxedDispatcher } as RequestInit;
    }
  } catch { /* url inválida */ }
  return {};
}

export class CheerioExtractor implements Extractor {
  async extract(url: string): Promise<ScrapedRawData> {
    try {
      const response = await fetch(url, {
        ...fetchOptions(url),
        headers: {
          'User-Agent':
            'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
          'Accept-Language': 'es-ES,es;q=0.9',
        },
      });

      if (!response.ok) {
        throw new Error(`HTTP Error: ${response.status} ${response.statusText}`);
      }

      const html = await response.text();
      const $ = cheerio.load(html);

      // Extraer JSON-LD ANTES de eliminar scripts (mejora calidad de extracción)
      let jsonLdText = '';
      $('script[type="application/ld+json"]').each((_, el) => {
        try {
          const raw = $(el).html() ?? '';
          const data = JSON.parse(raw);
          const items = Array.isArray(data) ? data : [data];
          for (const item of items) {
            if (item['@type'] === 'Event' || item['@type'] === 'Article') {
              jsonLdText += `\n[DATOS ESTRUCTURADOS JSON-LD]\n${JSON.stringify(item, null, 2)}\n[FIN DATOS ESTRUCTURADOS]\n`;
            }
          }
        } catch { /* ignorar JSON-LD inválido */ }
      });

      // Extraer og:image antes de limpiar el HTML
      const rawOgImage =
        $('meta[property="og:image"]').attr('content') ||
        $('meta[name="twitter:image"]').attr('content') ||
        undefined;
      // Descartar imágenes de placeholder comunes (logotipos institucionales, fondos blancos)
      const PLACEHOLDER_PATTERNS = ['blanco', 'logobogota', 'placeholder', 'logo-bogota', 'default-image'];
      const ogImage = rawOgImage && !PLACEHOLDER_PATTERNS.some((p) => rawOgImage.toLowerCase().includes(p))
        ? rawOgImage
        : undefined;

      // Limpiar etiquetas ruidosas
      $('script, style, noscript, iframe, svg, path, nav, footer, header').remove();

      // Extraer texto limpio
      // text() en cheerio elimina los tags HTML, nos deja el "texto crudo"
      const rawText = (jsonLdText + '\n' + $('body').text());
      
      // Limpiar un poco los saltos de línea y espacios en blanco extremos
      const cleanText = rawText
        .replace(/\s\s+/g, ' ')
        .replace(/\n\s*\n/g, '\n')
        .trim();

      return {
        url,
        sourceText: cleanText,
        html,
        ogImage,
        extractedAt: new Date(),
        status: 'SUCCESS',
      };
    } catch (error: unknown) {
      return {
        url,
        sourceText: '',
        extractedAt: new Date(),
        status: 'FAILED',
        error: getErrorMessage(error),
      };
    }
  }

  /**
   * Extrae texto limpio de un HTML ya cargado (sin hacer fetch).
   * Útil para construir ScrapedRawData desde HTML previamente descargado.
   */
  static textFromHtml(html: string): string {
    try {
      const $ = cheerio.load(html);
      $('script, style, noscript, iframe, svg, path, nav, footer, header').remove();
      const rawText = $('body').text();
      return rawText
        .replace(/\s\s+/g, ' ')
        .replace(/\n\s*\n/g, '\n')
        .trim();
    } catch {
      return '';
    }
  }

  async extractLinks(url: string): Promise<DiscoveredLink[]> {
    const response = await fetch(url, {
      ...fetchOptions(url),
      headers: {
        'User-Agent':
          'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
        'Accept-Language': 'es-ES,es;q=0.9',
      },
    });

    if (!response.ok) {
      throw new Error(`HTTP Error: ${response.status} ${response.statusText}`);
    }

    const html = await response.text();
    const $ = cheerio.load(html);
    const baseUrl = new URL(url);
    const seen = new Set<string>();
    const links: DiscoveredLink[] = [];

    $('a[href]').each((_, el) => {
      const href = $(el).attr('href');
      if (!href) return;

      // Ignorar anchors, mailto, javascript, tel
      if (href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('javascript:') || href.startsWith('tel:')) return;

      // Resolver URL relativa a absoluta
      let absoluteUrl: string;
      try {
        absoluteUrl = new URL(href, url).href;
      } catch {
        return;
      }

      // Solo links del mismo dominio
      try {
        const linkHost = new URL(absoluteUrl).hostname;
        if (linkHost !== baseUrl.hostname) return;
      } catch {
        return;
      }

      // Eliminar fragment y trailing slash para deduplicar
      const clean = absoluteUrl.split('#')[0].replace(/\/$/, '');
      if (seen.has(clean)) return;
      seen.add(clean);

      // Ignorar la propia URL de listado
      if (clean === url.replace(/\/$/, '')) return;

      const anchorText = $(el).text().replace(/\s+/g, ' ').trim();
      links.push({ url: clean, anchorText: anchorText || clean });
    });

    return links;
  }

  async extractLinksAllPages(baseUrl: string, maxPages: number = 50): Promise<DiscoveredLink[]> {
    const allLinks: DiscoveredLink[] = [];
    const seenUrls = new Set<string>();
    let currentUrl = baseUrl;
    let pageNum = 1;

    while (true) {
      log.info(`Extrayendo links de página ${pageNum}: ${currentUrl}`);
      const pageLinks = await this.extractLinks(currentUrl);

      let newCount = 0;
      for (const link of pageLinks) {
        if (!seenUrls.has(link.url)) {
          seenUrls.add(link.url);
          allLinks.push(link);
          newCount++;
        }
      }
      log.info(`Página ${pageNum}: ${newCount} links nuevos (${allLinks.length} total acumulado)`);

      // Buscar link a siguiente página
      const nextPageUrl = await this.findNextPage(currentUrl, pageNum);
      if (!nextPageUrl) {
        log.info(`No se encontró página siguiente. Total páginas: ${pageNum}`);
        break;
      }

      currentUrl = nextPageUrl;
      pageNum++;

      // Seguridad: respetar límite de páginas
      if (pageNum > maxPages) {
        log.warn(`Límite de ${maxPages} páginas alcanzado.`);
        break;
      }
    }

    return allLinks;
  }

  private async findNextPage(currentUrl: string, currentPage: number): Promise<string | null> {
    const response = await fetch(currentUrl, {
      ...fetchOptions(currentUrl),
      headers: {
        'User-Agent':
          'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36',
        'Accept-Language': 'es-ES,es;q=0.9',
      },
    });

    if (!response.ok) return null;

    const html = await response.text();
    const $ = cheerio.load(html);
    const baseUrl = new URL(currentUrl);

    // Estrategia 1: Buscar link con texto "Siguiente", "Next", "›", "»"
    const nextPatterns = ['siguiente', 'next', '›', '»', '>>'];
    for (const pattern of nextPatterns) {
      const link = $(`a`).filter((_, el) => {
        const text = $(el).text().trim().toLowerCase();
        return text === pattern || text.includes(pattern);
      }).first();

      if (link.length) {
        const href = link.attr('href');
        if (href) {
          try {
            return new URL(href, currentUrl).href;
          } catch { /* ignorar */ }
        }
      }
    }

    // Estrategia 2: Buscar link con ?page=N+1 o &page=N+1
    const nextPage = currentPage + 1;
    const pageLink = $(`a[href*="page=${nextPage}"]`).first();
    if (pageLink.length) {
      const href = pageLink.attr('href');
      if (href) {
        try {
          return new URL(href, currentUrl).href;
        } catch { /* ignorar */ }
      }
    }

    return null;
  }

  /**
   * Extract all URLs from a sitemap index (XML).
   * Handles both sitemap indexes (with <sitemap> entries) and plain sitemaps (with <url> entries).
   * @param sitemapUrl  URL of the sitemap index (e.g. https://example.com/sitemap.xml)
   * @param urlPatterns Optional array of strings — only URLs containing at least one pattern are returned
   */
  async extractSitemapLinks(sitemapUrl: string, urlPatterns: string[] = []): Promise<DiscoveredLink[]> {
    const headers = {
      'User-Agent': 'Mozilla/5.0 (compatible; Googlebot/2.1; +http://www.google.com/bot.html)',
      'Accept': 'application/xml,text/xml,*/*',
    };

    const fetchXml = async (url: string): Promise<string> => {
      const res = await fetch(url, { ...fetchOptions(url), headers });
      if (!res.ok) throw new Error(`HTTP ${res.status} fetching sitemap: ${url}`);
      return res.text();
    };

    type SitemapEntry = { loc: string; lastmod?: string };

    const collectEntries = async (xmlText: string): Promise<SitemapEntry[]> => {
      const $ = cheerio.load(xmlText, { xmlMode: true });
      // Sitemap index: contains <sitemap><loc>...</loc></sitemap>
      const childSitemaps = $('sitemap > loc').map((_, el) => $(el).text().trim()).get();
      if (childSitemaps.length > 0) {
        const nested: SitemapEntry[] = [];
        for (const childUrl of childSitemaps) {
          try {
            const childXml = await fetchXml(childUrl);
            nested.push(...(await collectEntries(childXml)));
          } catch (err: unknown) {
            log.warn(`Error fetching child sitemap ${childUrl}: ${getErrorMessage(err)}`);
          }
        }
        return nested;
      }
      // Plain sitemap: contains <url><loc>...</loc><lastmod>...</lastmod></url>
      const entries: SitemapEntry[] = [];
      $('url').each((_, el) => {
        const loc = $(el).find('loc').text().trim();
        const lastmodRaw = $(el).find('lastmod').text().trim();
        if (loc) entries.push({ loc, lastmod: lastmodRaw || undefined });
      });
      return entries;
    };

    log.info(`Leyendo sitemap: ${sitemapUrl}`);
    const xml = await fetchXml(sitemapUrl);
    const allEntries = await collectEntries(xml);
    log.info(`Total URLs en sitemap: ${allEntries.length}`);

    const filteredEntries = urlPatterns.length > 0
      ? allEntries.filter((e) => urlPatterns.some((p) => e.loc.includes(p)))
      : allEntries;

    log.info(`URLs tras filtro de patrones: ${filteredEntries.length}`);

    const seen = new Set<string>();
    return filteredEntries
      .filter((e) => { if (seen.has(e.loc)) return false; seen.add(e.loc); return true; })
      .map((e) => ({ url: e.loc, anchorText: '', lastmod: e.lastmod }));
  }
}

import 'dotenv/config'
import { PrismaPg } from '@prisma/adapter-pg'
import { PrismaClient, ScrapingStatus } from '../../generated/prisma/client'

const adapter = new PrismaPg({ connectionString: process.env.DATABASE_URL! })
const prisma = new PrismaClient({ adapter })

export type RunStats = {
  itemsFound: number
  itemsNew: number
  itemsUpdated: number
  itemsDuplicated: number
  errorMessage?: string
  metadata?: Record<string, unknown>
}

export class ScrapingLogger {
  /**
   * Inicia un log de ejecución. Retorna el logId para pasarlo a completeRun.
   */
  async startRun(sourceId: string): Promise<string> {
    const log = await prisma.scrapingLog.create({
      data: {
        sourceId,
        status: ScrapingStatus.RUNNING,
        startedAt: new Date(),
      },
    })
    return log.id
  }

  /**
   * Finaliza el log con los resultados de la ejecución.
   */
  async completeRun(logId: string, stats: RunStats): Promise<void> {
    const status =
      stats.errorMessage && stats.itemsFound === 0
        ? ScrapingStatus.FAILED
        : stats.errorMessage
        ? ScrapingStatus.PARTIAL
        : ScrapingStatus.SUCCESS

    await prisma.scrapingLog.update({
      where: { id: logId },
      data: {
        finishedAt: new Date(),
        status,
        itemsFound: stats.itemsFound,
        itemsNew: stats.itemsNew,
        itemsUpdated: stats.itemsUpdated,
        itemsDuplicated: stats.itemsDuplicated,
        errorMessage: stats.errorMessage ?? null,
        metadata: (stats.metadata as any) ?? undefined,
      },
    })
  }

  /**
   * Actualiza lastRunAt, lastRunStatus y lastRunItems en ScrapingSource.
   */
  async updateSourceStatus(
    sourceId: string,
    status: ScrapingStatus,
    itemsFound: number
  ): Promise<void> {
    await prisma.scrapingSource.update({
      where: { id: sourceId },
      data: {
        lastRunAt: new Date(),
        lastRunStatus: status,
        lastRunItems: itemsFound,
        updatedAt: new Date(),
      },
    })
  }

  /**
   * Busca o crea un ScrapingSource por URL.
   */
  async getOrCreateSource(params: {
    name: string
    url: string
    platform: 'WEBSITE' | 'INSTAGRAM' | 'FACEBOOK' | 'TELEGRAM' | 'TIKTOK' | 'X' | 'WHATSAPP'
    scraperType: string
    cityId: string
    verticalId: string
  }): Promise<string> {
    const existing = await prisma.scrapingSource.findFirst({
      where: { url: params.url },
    })
    if (existing) return existing.id

    const created = await prisma.scrapingSource.create({
      data: {
        name: params.name,
        url: params.url,
        platform: params.platform,
        scraperType: params.scraperType,
        cityId: params.cityId,
        verticalId: params.verticalId,
        scheduleCron: '0 6 * * *', // default: 6am daily
        isActive: true,
      },
    })
    return created.id
  }
}

