const MAX_RETRIES = 3;
const RETRY_BASE_MS = 2000;

async function callWithRetry<T>(fn: () => Promise<T>, label: string, apiKey?: string): Promise<T> {
  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
    try {
      return await fn();
    } catch (error: unknown) {
      const err = error as { status?: number; httpStatusCode?: number; message?: string };
      const status = err?.status ?? err?.httpStatusCode ?? 0;
      const is429 = status === 429 || err?.message?.includes('429');
      const isRetryable = status === 503 || is429 || err?.message?.includes('503');

      if (isRetryable && attempt < MAX_RETRIES) {
        const delay = RETRY_BASE_MS * Math.pow(2, attempt - 1);
        log.warn(`[${label}] Error ${status || 'retryable'} (intento ${attempt}/${MAX_RETRIES}). Reintentando en ${delay}ms...`);
        await new Promise((r) => setTimeout(r, delay));
        continue;
      }
      // Último intento fallido con 429 → marcar cuota agotada
      if (is429 && apiKey) {
        await quota.markExhausted(apiKey).catch(() => {});
      }
      throw error;
    }
  }
  throw new Error(`[${label}] Agotados ${MAX_RETRIES} intentos`);
}

export class GeminiAnalyzer {
  private static lastRequestTime: number = 0;
  private static readonly MIN_REQUEST_INTERVAL_MS = 12000; // 5 RPM = 1 request per 12 seconds
  private static rateLimitEnabled = process.env.NODE_ENV !== 'test';

  // Selecciona la primera key disponible del pool y devuelve el modelo listo.
  // Retorna null si no hay keys configuradas (usar mockAnalysis).
  // Lanza [QUOTA_EXHAUSTED] si hay keys pero todas están agotadas.
  private async getModel(config: {
    systemInstruction?: string;
    maxOutputTokens: number;
  }): Promise<{ model: ReturnType<GoogleGenerativeAI['getGenerativeModel']>; apiKey: string } | null> {
    const raw = process.env.GEMINI_KEYS ?? process.env.GOOGLE_AI_STUDIO_KEY ?? '';
    const configured = raw.split(',').filter((k) => k.trim().length > 0);
    if (configured.length === 0) return null; // sin keys → mockAnalysis

    const apiKey = await getAvailableKey();
    if (!apiKey) {
      throw new Error('[QUOTA_EXHAUSTED] Todas las keys de Gemini están agotadas.');
    }
    const genAI = new GoogleGenerativeAI(apiKey);
    const model = genAI.getGenerativeModel({
      model: 'gemini-2.5-flash',
      ...(config.systemInstruction ? { systemInstruction: config.systemInstruction } : {}),
      generationConfig: {
        responseMimeType: 'application/json',
        temperature: 0.1,
        maxOutputTokens: config.maxOutputTokens,
      },
    });
    return { model, apiKey };
  }

  private async enforceRateLimit(): Promise<void> {
    if (!GeminiAnalyzer.rateLimitEnabled) return;

    const now = Date.now();
    const timeSinceLastRequest = now - GeminiAnalyzer.lastRequestTime;
    if (timeSinceLastRequest < GeminiAnalyzer.MIN_REQUEST_INTERVAL_MS) {
      const delayMs = GeminiAnalyzer.MIN_REQUEST_INTERVAL_MS - timeSinceLastRequest;
      log.info(`Esperando ${(delayMs / 1000).toFixed(1)}s para respetar 5 RPM...`);
      await new Promise((resolve) => setTimeout(resolve, delayMs));
    }
    GeminiAnalyzer.lastRequestTime = Date.now();
  }

  async analyze(sourceText: string, url: string): Promise<ActivityNLPResult> {
    const modelResult = await this.getModel({ systemInstruction: SYSTEM_PROMPT, maxOutputTokens: 8192 });
    if (!modelResult) {
      log.warn('⚠️ GOOGLE_AI_STUDIO_KEY no encontrada. Usando resultado MOCK.');
      return this.mockAnalysis(url);
    }

    const truncatedText = sourceText.substring(0, 6000);
    const userMessage = `URL de origen: ${url}\n\nTEXTO CRUDO EXTRAÍDO:\n${truncatedText}`;

    try {
      const { model, apiKey } = modelResult;

      await this.enforceRateLimit();
      const result = await callWithRetry(
        () => model.generateContent(userMessage),
        'GEMINI',
        apiKey,
      );
      const rawText = result.response.text();

      // Limpiar posible markdown wrapping o whitespace
      const jsonStr = rawText
        .replace(/^```(?:json)?\s*/i, '')
        .replace(/\s*```\s*$/, '')
        .trim();

      log.info(`Respuesta raw (primeros 500 chars): ${rawText.substring(0, 500)}`);

      let parsed: unknown;
      try {
        parsed = JSON.parse(jsonStr);
      } catch (parseErr: unknown) {
        const msg = parseErr instanceof Error ? parseErr.message : String(parseErr);
        throw new Error(`Gemini retornó JSON inválido (${msg}): ${jsonStr.substring(0, 300)}`);
      }

      // Gemini a veces devuelve array en lugar de objeto — tomar el primer elemento
      if (Array.isArray(parsed)) {
        log.warn('Respuesta es array, tomando primer elemento.');
        parsed = parsed[0];
      }

      // Si Gemini indica baja confianza (nada útil encontrado), devolver resultado vacío válido
      const rawParsed = parsed as Record<string, unknown>;

      // Rechazo semántico temprano: Gemini NO declaró explícitamente que es una actividad (incluye null/undefined)
      // Esto frena noticias, convocatorias, PQRS, y actúa como fail-safe si el schema se corrompe
      if (rawParsed.isActivity !== true) {
        log.info(`[GEMINI:isActivity=false] Contenido rechazado semánticamente (fail-safe): ${url}`);
        return {
          title: 'No es actividad',
          description: '',
          categories: ['General'],
          audience: 'ALL' as const,
          isActivity: false,
          confidenceScore: 0,
          currency: 'COP',
        };
      }

      if (rawParsed.confidenceScore !== undefined && Number(rawParsed.confidenceScore) < 0.1) {
        log.warn('Confianza < 0.1 — el contenido no parece ser una actividad infantil.');
        return {
          isActivity: false,
          title: 'No identificado',
          description: `No se encontró información de actividad infantil en ${url}`,
          categories: ['Sin categoría'],
          audience: 'ALL' as const,
          confidenceScore: 0,
          currency: 'COP',
        };
      }

      const sanitized = sanitizeGeminiResponse(parsed as Record<string, unknown>);
      const validated = activityNLPResultSchema.safeParse(sanitized);
      if (!validated.success) {
        log.error('Zod validation errors', { issues: validated.error.issues, raw: JSON.stringify(sanitized).substring(0, 300) });
        throw new Error(
          `Respuesta de Gemini no cumple el schema: ${validated.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join(', ')}`,
        );
      }

      return validated.data;
    } catch (error: unknown) {
      log.error('Error en GeminiAnalyzer', { error });
      throw error;
    }
  }

  async discoverActivityLinks(links: DiscoveredLink[], sourceUrl: string): Promise<string[]> {
    // Extensiones de archivo que nunca son páginas de actividades
    const IMAGE_OR_BINARY_EXT = /\.(jpe?g|png|gif|webp|svg|bmp|tiff?|pdf|mp4|mp3|zip|doc[x]?|xls[x]?|ppt[x]?)$/i;

    // Pre-filtro Stage 1: URLs que son claramente navegación/filtro/archivos
    const stage1Filtered = links.filter((l) => {
      try {
        const u = new URL(l.url);
        if (!['http:', 'https:'].includes(u.protocol)) return false; // mailto:, tel:, javascript:
        if (u.search.length > 0) return false;                        // query params
        if (u.hash && u.pathname === '/' || u.hash.length > 0 && u.pathname === u.hash) return false; // hash-only
        if (IMAGE_OR_BINARY_EXT.test(u.pathname)) return false;       // archivos binarios
        return true;
      } catch {
        return false;
      }
    });
    const stage1Excluded = links.length - stage1Filtered.length;
    if (stage1Excluded > 0) {
      log.info(`Pre-filtro Stage 1: ${stage1Excluded} URLs excluidas (query params o archivos binarios).`);
    }

    // Pre-filtro Stage 2: análisis de URL productividad (nuevo — S34)
    const urlClassifierResult = preFilterUrls(stage1Filtered.map((l) => l.url), 45);
    const stage2Excluded = urlClassifierResult.stats.filtered;

    if (stage2Excluded > 0) {
      log.info(`Pre-filtro Stage 2 (URL classifier): ${stage2Excluded} URLs excluidas (patrón no productivo).`);
      // Log algunos ejemplos de URLs excluidas
      const examples = urlClassifierResult.stats.scores
        .filter((s) => !urlClassifierResult.kept.includes(s.url))
        .slice(0, 3)
        .map((s) => `${s.url} (score ${s.score})`)
        .join('; ');
      if (examples) {
        log.debug(`Ejemplos excluidos: ${examples}`);
      }
    }

    // Filtrar links basado en URLs que pasaron ambos filtros
    const filtered = links.filter((l) => urlClassifierResult.kept.includes(l.url));
    const totalExcluded = links.length - filtered.length;
    if (totalExcluded > 0) {
      const rejectedUrls = links.filter((l) => !filtered.some((f) => f.url === l.url)).map((l) => l.url);
      const sample = rejectedUrls.slice(0, 5);
      log.info(`[DISCOVER_FILTER]`, {
        raw: links.length,
        accepted: filtered.length,
        rejected: totalExcluded,
        reductionPct: `${Math.round((totalExcluded / links.length) * 100)}%`,
        sample_rejected: sample,
      });
    }

    // 100 URLs por lote (benchmark S34: chunk=100 reduce riesgo por quota-429)
    // Gemini free tier: 20 req/día — 100 URLs/lote balancea # llamadas vs riesgo de fallo
    // Banrep Bogotá (1.083 URLs) → 11 lotes (vs 6 con 200, vs 22 con 50)
    const CHUNK_SIZE = 100;
    const chunks: DiscoveredLink[][] = [];
    for (let i = 0; i < filtered.length; i += CHUNK_SIZE) {
      chunks.push(filtered.slice(i, i + CHUNK_SIZE));
    }

    log.info(`Procesando ${filtered.length} links en ${chunks.length} lotes de ${CHUNK_SIZE}`);

    const modelResult = await this.getModel({ maxOutputTokens: 8192 });
    if (!modelResult) {
      log.warn('⚠️ GOOGLE_AI_STUDIO_KEY no encontrada. Retornando todos los links.');
      return links.map((l) => l.url);
    }
    const { model, apiKey } = modelResult;

    const allActivityUrls: string[] = [];
    // Trackea el último error retryable (429/503) para propagarlo si todos los lotes fallan
    let lastRetryableError: unknown = null;

    for (let chunkIndex = 0; chunkIndex < chunks.length; chunkIndex++) {
      const chunk = chunks[chunkIndex];
      const linksText = chunk
        .map((l, i) => `${i + 1}. URL: ${l.url} | Texto: ${l.anchorText}`)
        .join('\n');

      const prompt = `Eres un filtro inteligente para la plataforma HabitaPlan.
Te doy una lista numerada de links extraídos de: ${sourceUrl}

Tu tarea: selecciona SOLO los links que probablemente lleven a páginas de actividades, eventos, talleres, cursos o programas para niños, jóvenes o familias.

EXCLUYE: links de navegación general (inicio, contacto, nosotros, login, redes sociales), políticas de privacidad, páginas corporativas.

INCLUYE: links a eventos específicos, talleres, cursos, programas culturales, actividades recreativas, clubes de lectura, etc.

Responde con JSON: { "indices": [1, 3, 7, ...] }
Los números son los índices (posición en la lista, comenzando en 1) de los links seleccionados.
Si ningún link parece ser una actividad, devuelve { "indices": [] }

LINKS:
${linksText}`;

      try {
        await this.enforceRateLimit();
        const result = await callWithRetry(
          () => model.generateContent(prompt),
          `GEMINI-DISCOVER-lote${chunkIndex + 1}`,
          apiKey,
        );
        const rawText = result.response.text();
        const jsonStr = rawText
          .replace(/^```(?:json)?\s*/i, '')
          .replace(/\s*```\s*$/, '')
          .trim();

        let parsed: unknown;
        try {
          parsed = JSON.parse(jsonStr);
        } catch (parseErr: unknown) {
          const msg = parseErr instanceof Error ? parseErr.message : String(parseErr);
          log.error(`Lote ${chunkIndex + 1}: JSON inválido (${msg})`);
          continue;
        }

        const validated = discoveredActivityUrlsSchema.safeParse(parsed);
        if (!validated.success) {
          log.error(`Lote ${chunkIndex + 1}: Validación falló`);
          continue;
        }

        // Mapear índices (1-based) de vuelta a URLs
        const found = validated.data.indices
          .filter((idx) => idx >= 1 && idx <= chunk.length)
          .map((idx) => chunk[idx - 1].url);
        log.info(`Lote ${chunkIndex + 1}/${chunks.length}: ${found.length} actividades encontradas`);
        allActivityUrls.push(...found);
      } catch (error: unknown) {
        if (isRetryableError(error)) {
          // Guardar para re-lanzar al final si no hay resultados (permite fallback en parser.ts)
          lastRetryableError = error;
          log.warn(`Lote ${chunkIndex + 1}: Gemini no disponible (retryable). Continuando con otros lotes...`);
        } else {
          log.error(`Lote ${chunkIndex + 1} Error: ${error instanceof Error ? error.message : String(error)}`, { error });
        }
      }
    }

    // Si hubo errores retryables y no se obtuvieron resultados de ningún lote,
    // re-lanzar para que discoverWithFallback active el fallback conservador.
    // Si hay resultados parciales (algún lote exitoso), usarlos en vez del fallback.
    if (allActivityUrls.length === 0 && lastRetryableError !== null) {
      throw lastRetryableError;
    }

    log.info(`Total actividades identificadas: ${allActivityUrls.length}`);
    return allActivityUrls;
  }

  /**
   * Analyze an Instagram post caption + profile bio to extract activity data.
   * Uses a prompt adapted for short captions, hashtags, and emojis.
   */
  async analyzeInstagramPost(post: InstagramPost, profileBio: string): Promise<ActivityNLPResult> {
    const modelResult = await this.getModel({ systemInstruction: INSTAGRAM_SYSTEM_PROMPT, maxOutputTokens: 4096 });
    if (!modelResult) {
      log.warn('⚠️ GOOGLE_AI_STUDIO_KEY no encontrada. Usando resultado MOCK.');
      return this.mockAnalysis(post.url);
    }

    const userMessage = `POST DE INSTAGRAM:
URL: ${post.url}
Fecha: ${post.timestamp ?? 'No disponible'}
Likes: ${post.likesCount ?? 'No disponible'}

CAPTION DEL POST:
${post.caption}

BIO DEL PERFIL:
${profileBio}`;

    try {
      const { model, apiKey } = modelResult;

      await this.enforceRateLimit();
      const result = await callWithRetry(
        () => model.generateContent(userMessage),
        'GEMINI-IG',
        apiKey,
      );
      const rawText = result.response.text();

      const jsonStr = rawText
        .replace(/^```(?:json)?\s*/i, '')
        .replace(/\s*```\s*$/, '')
        .trim();

      log.info(`Respuesta raw (primeros 300 chars): ${rawText.substring(0, 300)}`);

      let parsed: unknown;
      try {
        parsed = JSON.parse(jsonStr);
      } catch (parseErr: unknown) {
        const msg = parseErr instanceof Error ? parseErr.message : String(parseErr);
        throw new Error(`Gemini retornó JSON inválido para Instagram (${msg}): ${jsonStr.substring(0, 300)}`);
      }

      // Gemini a veces devuelve array en lugar de objeto — tomar el primer elemento
      if (Array.isArray(parsed)) {
        log.warn('Respuesta es array, tomando primer elemento.');
        parsed = parsed[0];
      }

      const rawParsed = parsed as Record<string, unknown>;
      if (rawParsed.confidenceScore !== undefined && Number(rawParsed.confidenceScore) < 0.1) {
        log.warn('Confianza < 0.1 — el post no parece ser una actividad infantil.');
        return {
          isActivity: false,
          title: 'No identificado',
          description: `No se encontró información de actividad infantil en ${post.url}`,
          categories: ['Sin categoría'],
          audience: 'ALL' as const,
          confidenceScore: 0,
          currency: 'COP',
        };
      }

      const sanitized = sanitizeGeminiResponse(parsed as Record<string, unknown>);
      const validated = activityNLPResultSchema.safeParse(sanitized);
      if (!validated.success) {
        log.error('Zod validation errors (IG)', { issues: validated.error.issues, raw: JSON.stringify(sanitized).substring(0, 300) });
        throw new Error(
          `Respuesta de Gemini-IG no cumple el schema: ${validated.error.issues.map((i) => `${i.path.join('.')}: ${i.message}`).join(', ')}`,
        );
      }

      return validated.data;
    } catch (error: unknown) {
      log.error('Error en GeminiAnalyzer (Instagram)', { error });
      throw error;
    }
  }

  private mockAnalysis(url: string): ActivityNLPResult {
    return {
      isActivity: true,
      title: 'Actividad Infantil (Mock)',
      description: `Extracción simulada de ${url}`,
      categories: ['General'],
      minAge: 4,
      maxAge: 12,
      price: 50000,
      pricePeriod: 'MONTHLY',
      currency: 'COP',
      audience: 'KIDS',
      location: { address: 'Calle Falsa 123', city: 'Bogotá' },
      schedules: null,
      confidenceScore: 0.85,
    };
  }
}

// =============================================================================
// parser.ts — Orchestrator de parsing resiliente
//
// Expone dos funciones públicas:
//
//   parseActivity(html, url, analyzer)
//     Fase 3: intenta Gemini; si falla con error retryable (429/503/timeout)
//     usa fallbackFromCheerio para no perder la actividad.
//
//   discoverWithFallback(links, sourceUrl, analyzer)
//     Fase 2: intenta Gemini para filtrar qué URLs son actividades;
//     si falla con error retryable, devuelve TODOS los URLs (conservador —
//     cero pérdida de actividades) y registra el fallback en métricas.
// =============================================================================

import type { ActivityNLPResult, DiscoveredLink, ScrapedRawData } from '../types';
import type { GeminiAnalyzer } from '../nlp/gemini.analyzer';
import { CheerioExtractor } from '../extractors/cheerio.extractor';
import { fallbackFromCheerio } from './fallback-mapper';
import { isRetryableError, _incrementMetric } from './parser.types';
import type { ParseResult } from './parser.types';
import { createLogger } from '../../../lib/logger';
import { preFilterUrls } from '../../../lib/url-classifier';

const log = createLogger('scraping:parser');

// Extensiones binarias — mismo criterio que Stage 1 en gemini.analyzer.ts
const IMAGE_OR_BINARY_EXT = /\.(jpe?g|png|gif|webp|svg|bmp|tiff?|pdf|mp4|mp3|zip|doc[x]?|xls[x]?|ppt[x]?)$/i;

/**
 * Aplica los mismos filtros determinísticos que Stage 1 + Stage 2 de discoverActivityLinks.
 * Usado en el fallback cuando Gemini no está disponible para no mandar basura a Fase 3.
 */
function applyDiscoverPreFilters(links: DiscoveredLink[]): string[] {
  // Stage 1: query params + extensiones binarias + fragmentos puros + protocolos no-http
  const stage1 = links.filter((l) => {
    try {
      const u = new URL(l.url);
      if (!['http:', 'https:'].includes(u.protocol)) return false; // mailto:, tel:, javascript:
      if (u.search.length > 0) return false;                        // query params
      if (u.hash && u.pathname === '/' || u.hash.length > 0 && u.pathname === u.hash) return false; // hash-only
      if (IMAGE_OR_BINARY_EXT.test(u.pathname)) return false;       // archivos binarios
      return true;
    } catch {
      return false; // URL inválida → descartar
    }
  });

  // Stage 2: url-classifier score (threshold 45 — mismo que el analyze normal)
  const stage2 = preFilterUrls(stage1.map((l) => l.url), 45);
  return stage2.kept;
}

// ── Fase 3: parseActivity ─────────────────────────────────────────────────────

/**
 * Intenta extraer y analizar una URL con Gemini.
 * Si Gemini falla con error retryable, usa fallbackFromCheerio.
 * Si la extracción HTML falla, relanza el error (no es problema de Gemini).
 *
 * @param html        HTML ya extraído (viene de CheerioExtractor.extract)
 * @param url         URL original (para logs y referencia)
 * @param raw         ScrapedRawData completo (para fallback con ogImage)
 * @param analyzer    Instancia de GeminiAnalyzer
 */
export async function parseActivity(
  html: string,
  url: string,
  raw: ScrapedRawData,
  analyzer: Pick<GeminiAnalyzer, 'analyze'>,
): Promise<ParseResult> {
  try {
    const result: ActivityNLPResult = await analyzer.analyze(html, url);
    _incrementMetric('geminiOk');
    return { result, source: 'gemini' };
  } catch (err: unknown) {
    if (isRetryableError(err)) {
      log.warn(`[parser] Gemini no disponible para ${url} (retryable). Usando fallback Cheerio.`);
      _incrementMetric('fallbackUsed');
      return fallbackFromCheerio(raw);
    }
    // Error no retryable (e.g. HTML vacío, respuesta inválida) → propagar
    _incrementMetric('geminiErrors');
    throw err;
  }
}

// ── Fase 2: discoverWithFallback ──────────────────────────────────────────────

/**
 * Intenta usar Gemini para filtrar qué URLs son actividades.
 * Si Gemini falla con error retryable, devuelve TODOS los URLs como fallback
 * (estrategia conservadora: mejor procesar demás que perder actividades).
 *
 * @param links      Lista de DiscoveredLink del crawl
 * @param sourceUrl  URL de la página listado (para contexto de Gemini)
 * @param analyzer   Instancia de GeminiAnalyzer
 * @returns          Array de URL strings (ya filtrados o todos si fallback)
 */
export async function discoverWithFallback(
  links: DiscoveredLink[],
  sourceUrl: string,
  analyzer: Pick<GeminiAnalyzer, 'discoverActivityLinks'>,
): Promise<string[]> {
  if (links.length === 0) return [];

  try {
    const filtered = await analyzer.discoverActivityLinks(links, sourceUrl);
    _incrementMetric('discoverOk');
    return filtered;
  } catch (err: unknown) {
    if (isRetryableError(err)) {
      // Aplicar los mismos pre-filtros determinísticos (Stage 1 + Stage 2) que usa discoverActivityLinks.
      // Sin esto el fallback manda TODOS los links brutos (fragmentos, imágenes, wp-uploads) a Fase 3.
      const safeUrls = applyDiscoverPreFilters(links);
      log.warn(
        `[parser] Gemini no disponible para discover en ${sourceUrl} (retryable). ` +
        `Fallback conservador: ${safeUrls.length}/${links.length} URLs tras pre-filtros.`,
      );
      _incrementMetric('discoverFallback');
      return safeUrls;
    }
    // Error no retryable → propagar
    throw err;
  }
}

// ── Re-export helpers ─────────────────────────────────────────────────────────

export { fallbackFromCheerio } from './fallback-mapper';
export { isRetryableError, getParserMetrics, resetParserMetrics } from './parser.types';
export type { ParseResult } from './parser.types';

import { getErrorMessage } from '../../../lib/error';
import { PrismaClient } from '../../../generated/prisma/client';
import { createLogger } from '../../../lib/logger';

const log = createLogger('quality:category-skew');

export type CategoryStat = {
  name: string;
  count: number;
  percentage: number;
};

export function computeCategoryDistribution(rows: { name: string; count: number }[]): CategoryStat[] {
  const total = rows.reduce((acc, r) => acc + r.count, 0);
  if (total === 0) return [];

  return rows.map(r => ({
    name: r.name,
    count: r.count,
    percentage: r.count / total
  }));
}

export function detectAnomalies(stats: CategoryStat[]) {
  return stats
    .filter(s => s.percentage > 0.25)
    .map(s => ({
      category: s.name,
      percentage: s.percentage, // float 0-1
      level: s.percentage > 0.4 ? 'critical' : 'warning'
    }));
}

import { prisma } from '../../../lib/db';

/**
 * Hook to be fired post-ingestion.
 * Evaluates DB categories directly.
 */
export async function runCategorySkewGuardrail(): Promise<void> {
  try {
    const rawCategories = await prisma.category.findMany({
      select: {
        name: true,
        _count: { select: { activities: true } }
      }
    });

    const rows = rawCategories.map(c => ({
      name: c.name,
      count: c._count.activities
    }));

    const stats = computeCategoryDistribution(rows);
    const anomalies = detectAnomalies(stats);

    if (anomalies.length > 0) {
      log.warn('CATEGORY_SKEW_DETECTED', { anomalies });

      // Optional: Store this signal in DB (e.g. ContentQualityMetric) or alert system
      // We will leave the warning log which Vercel/Datadog picks up instantly.
    } else {
      log.info('Distribución de categorías en niveles saludables (<25%).');
    }
  } catch (err: unknown) {
    log.error('Error in runCategorySkewGuardrail', { error: getErrorMessage(err) });
  }
}

import { ActivityNLPResult } from '../types';
import { isDomainSpecificNoise } from './domain-noise-rules';
import { createLogger } from '../../../lib/logger';

const log = createLogger('scraping:trust-layer');

export interface PublishValidationResult {
  action: 'PUBLISH' | 'QUARANTINE' | 'REJECT';
  reason: string;
  // 'QUARANTINE' maps to ActivityStatus.PAUSED — reversible, not public
  // 'REJECT' maps to DISCARDED_QUALITY — not persisted
  // 'PUBLISH' maps to ActivityStatus.ACTIVE
}

const DEFAULT_PAST_TOLERANCE_DAYS = 3;
const DOMAIN_PAST_TOLERANCE: Record<string, number> = {
  'cinematecadebogota.gov.co': 7,
  'idartes.gov.co': 14,
  'banrepcultural.org': 14,
  'museonacional.gov.co': 14,
};

export function validateForPublish(
  activity: ActivityNLPResult,
  sourceUrl: string
): PublishValidationResult {
  const title = activity.title || '';
  const startDate = activity.schedules?.[0]?.startDate ? new Date(activity.schedules[0].startDate) : null;
  const confidence = activity.confidenceScore ?? 0;
  
  let hostname = '';
  try { hostname = new URL(sourceUrl).hostname.replace('www.', ''); } catch { /* ignore */ }

  // ── 1. HARD REJECTS (Basura clara) ──

  // A. Ruido Corporativo (PQRS, /producto/, etc)
  if (isDomainSpecificNoise(sourceUrl, title)) {
    return { action: 'REJECT', reason: 'domain_noise_or_global_keyword' };
  }

  // B. Fechas alucinadas (Ej: > 540 días en el futuro)
  if (startDate) {
    const maxFutureDate = new Date();
    maxFutureDate.setDate(maxFutureDate.getDate() + 540);
    if (startDate > maxFutureDate) {
      return { action: 'REJECT', reason: 'future_date_hallucination' };
    }
  }

  // C. Empty content reject (título corto + sin descripción + sin fecha)
  if (title.length < 15 && !activity.description && !startDate) {
    return { action: 'REJECT', reason: 'empty_content' };
  }

  // ── 2. QUARANTINE (Duda razonable -> guardar como PAUSED) ──

  // D. Evento Expirado (pasó hace más de X días)
  if (startDate) {
    // Si hace match con dominios o subdominios
    const matchedDomain = Object.keys(DOMAIN_PAST_TOLERANCE).find(
      domain => hostname === domain || hostname.endsWith(`.${domain}`)
    );
    const tolerance = matchedDomain ? DOMAIN_PAST_TOLERANCE[matchedDomain] : DEFAULT_PAST_TOLERANCE_DAYS;
    
    const pastToleranceDate = new Date();
    pastToleranceDate.setDate(pastToleranceDate.getDate() - tolerance);
    pastToleranceDate.setHours(0, 0, 0, 0);
    
    const startWithoutTime = new Date(startDate);
    startWithoutTime.setHours(0, 0, 0, 0);

    if (startWithoutTime < pastToleranceDate) {
      // Hard reject para cosas exageradamente viejas (ej: evento 2024 insertado en 2026) -> 180 días max
      const extremePastDate = new Date();
      extremePastDate.setDate(extremePastDate.getDate() - 180);
      if (startWithoutTime < extremePastDate) {
         return { action: 'REJECT', reason: 'extreme_past_date' };
      }
      return { action: 'QUARANTINE', reason: `past_date_soft_${tolerance}d` };
    }
  }

  // E. Sin fecha
  if (!startDate) {
    if (confidence < 0.65) {
      return { action: 'QUARANTINE', reason: 'missing_date_low_confidence' };
    } else {
      // Sin fecha pero alta confianza (puede ser exposición permanente o campaña)
      return { action: 'QUARANTINE', reason: 'missing_date_high_confidence' };
    }
  }

  // F. Score medio
  if (confidence < 0.4) {
    return { action: 'QUARANTINE', reason: 'medium_score' };
  }

  // ── 3. PUBLISH (Todo sólido) ──
  return { action: 'PUBLISH', reason: 'ok' };
}

import { getErrorMessage } from '../../lib/error';
import { createLogger } from '../../lib/logger';
import { prisma } from '../../lib/db';
import { InstagramExtractOptions } from './extractors/playwright.extractor';
import { ScrapedRawData, InstagramProfileData } from './types';

/**
 * Interfaces mínimas: solo los métodos que getSourceStrategies realmente invoca.
 * Los mocks de tests y las clases reales satisfacen esta interfaz por structural typing.
 */
interface CheerioLike {
  extract(url: string): Promise<ScrapedRawData>;
}

interface PlaywrightLike {
  extractWebText(url: string): Promise<ScrapedRawData>;
  extractProfile(url: string, opts: InstagramExtractOptions): Promise<InstagramProfileData>;
}

/** Factories que el pipeline inyecta para obtener extractores bajo demanda. */
export interface ExtractorFactory {
  cheerio: () => CheerioLike;
  playwright: () => PlaywrightLike;
}

const log = createLogger('scraping:resilience');

/* ============================================================================
 * ERROR CLASSIFICATION
 * ============================================================================ */
export type NormalizedErrorType = 'timeout' | 'blocked' | 'parse_error' | 'empty_response' | 'unknown';

export function classifyError(error: any): NormalizedErrorType {
  const message = (getErrorMessage(error) || error?.toString() || '').toLowerCase();
  const status = error?.status || error?.response?.status;

  if (message.includes('timeout') || message.includes('abort') || message.includes('connreset')) {
    return 'timeout';
  }
  if (status === 403 || status === 429 || message.includes('forbidden') || message.includes('captcha') || message.includes('rate limit')) {
    return 'blocked';
  }
  if (message.includes('parse') || message.includes('json') || message.includes('syntax')) {
    return 'parse_error';
  }
  if (message.includes('empty') || message.includes('no extractable')) {
    return 'empty_response';
  }
  return 'unknown';
}

/* ============================================================================
 * RETRIES INTELIGENTES (BACKOFF)
 * ============================================================================ */
export interface FetchRetryResult {
  data: string;
  responseTime: number;
  methodUsed: string;
}

export async function fetchWithRetry(
  fetchFn: () => Promise<string>,
  methodName: string,
  maxRetries = 3
): Promise<FetchRetryResult> {
  let attempt = 1;
  const start = Date.now();

  while (attempt <= maxRetries) {
    try {
      const data = await fetchFn();
      
      if (!data || data.trim().length === 0) {
        throw new Error('empty_response');
      }

      return {
        data,
        responseTime: Date.now() - start,
        methodUsed: methodName,
      };
    } catch (error: unknown) {
      const errType = classifyError(error);
      const latency = Date.now() - start;

      log.info(JSON.stringify({
        event: 'scrape_retry',
        method: methodName,
        attempt,
        responseTime: latency,
        errorType: errType,
        message: getErrorMessage(error)
      }));

      if (attempt === maxRetries || errType === 'blocked') {
        throw error; // Al quedarse sin reintentos o recibir un hard block
      }
      
      const delay = Math.pow(2, attempt) * 1000;
      await new Promise(res => setTimeout(res, delay));
      attempt++;
    }
  }

  throw new Error('Agotados reintentos');
}

/* ============================================================================
 * FALLBACKS POR FUENTE
 * ============================================================================ */
export type ScraperStrategyBuilder = () => Promise<string>;

export function getSourceStrategies(sourceType: string, extractors: ExtractorFactory, url: string): ScraperStrategyBuilder[] {
  // Configurable based on known platform capabilities
  if (sourceType === 'WEBSITE') {
    return [
      () => extractors.cheerio().extract(url).then((res: ScrapedRawData) => {
        if (res.status === 'FAILED' || (res.sourceText?.length ?? 0) < 50) throw new Error('Cheerio insuficient logic');
        // Devolvemos el HTML completo (no sólo sourceText) para que rawForFallback.html
        // tenga tags reales (<title>, <h1>, og:title) y fallback-mapper pueda extraer título.
        return res.html ?? res.sourceText;
      }),
      () => extractors.playwright().extractWebText(url).then((res: ScrapedRawData) => {
         if (res.status === 'FAILED') throw new Error(res.error ?? 'Playwright failed');
         return res.sourceText;
      })
    ];
  }

  if (sourceType === 'INSTAGRAM') {
    return [
      () => extractors.playwright().extractProfile(url, { maxPosts: 1 }).then((res: InstagramProfileData) => JSON.stringify(res))
    ];
  }

  return [];
}

export async function fetchWithFallback(
  sourceUrl: string,
  sourceType: string,
  extractorsConfig: ExtractorFactory
): Promise<FetchRetryResult> {
  const strategies = getSourceStrategies(sourceType, extractorsConfig, sourceUrl);

  for (let i = 0; i < strategies.length; i++) {
    const methodName = `Strategy_#${i+1}`;
    try {
      const result = await fetchWithRetry(strategies[i], methodName, 2);
      
      log.info(JSON.stringify({
        event: 'scrape_success',
        source: sourceType,
        url: sourceUrl,
        method: methodName,
        responseTime: result.responseTime,
        timestamp: new Date().toISOString()
      }));

      return result;
    } catch (error: unknown) {
      log.info(JSON.stringify({
        event: 'scrape_fallback',
        source: sourceType,
        url: sourceUrl,
        methodFailed: methodName,
        errorType: classifyError(error),
        timestamp: new Date().toISOString()
      }));
      
      // Si fue la última estrategia, el fallo es definitivo
      if (i === strategies.length - 1) {
        log.info(JSON.stringify({
          event: 'scrape_failed',
          source: sourceType,
          url: sourceUrl,
          reason: 'All strategies exhausted',
          timestamp: new Date().toISOString()
        }));
        throw error;
      }
    }
  }

  throw new Error('Sin estrategias validables');
}

/* ============================================================================
 * HEALTH SCORING
 * ============================================================================ */
export interface SourceHealthResult {
  success: boolean;
  responseTimeMs: number;
}

export async function updateSourceHealth(sourceHost: string, result: SourceHealthResult): Promise<void> {
  try {
    const current = await prisma.sourceHealth.findUnique({ where: { source: sourceHost } });
    
    // Fallback if not tracked yet
    const base = current ?? {
      successCount: 0,
      errorCount: 0,
      avgResponseMs: 0,
    };

    const newSuccessCount = result.success ? base.successCount + 1 : base.successCount;
    const newErrorCount = result.success ? base.errorCount : base.errorCount + 1;
    const totalRequests = newSuccessCount + newErrorCount;

    // Media Móvil Simple
    const newAvgResponse = Math.floor(
      (base.avgResponseMs * (totalRequests - 1) + result.responseTimeMs) / totalRequests
    );

    // Scoring calculation (capped latency penalty prevents pure Playwright domains from failing natively)
    const successRate = newSuccessCount / totalRequests;
    const errorRate = newErrorCount / totalRequests;
    
    const MAX_LATENCY_MS = 3000;
    const latencyFactor = Math.min(newAvgResponse, MAX_LATENCY_MS) / MAX_LATENCY_MS;

    let newScore = (successRate * 0.6) - (errorRate * 0.3) - (latencyFactor * 0.1);
    if (newScore < 0) newScore = 0;
    if (newScore > 1) newScore = 1;

    // 1. Evitar "cold start bias" en score (no ser 1.0 artificialmente)
    if (totalRequests < 5) {
      newScore = 0.5; // neutral
    }
    // 2. Evitar sobre-penalización por pocos errores
    else if (totalRequests < 10) {
      newScore = (newScore + 0.5) / 2; // suavizado progresivo
    }

    // 3. Floor por éxito reciente: si la fuente tuvo éxito en los últimos 7 días,
    //    el promedio histórico de errores no puede ocultarla completamente del portal.
    //    Mínimo 0.15 garantiza que sigue siendo visible (badDomains threshold es 0.1).
    const recentSuccess = current?.lastSuccessAt
      && (Date.now() - new Date(current.lastSuccessAt).getTime()) < 7 * 24 * 60 * 60 * 1000;
    if (recentSuccess && newScore < 0.15) {
      newScore = 0.15;
    }

    let newStatus = 'healthy';
    if (newScore > 0.7) newStatus = 'healthy';
    else if (newScore >= 0.4) newStatus = 'degraded';
    else newStatus = 'critical';

    if (newStatus !== current?.status && newStatus === 'critical') {
      log.info(JSON.stringify({
        event: 'source_critical_penalty',
        source: sourceHost,
        score: newScore,
        timestamp: new Date().toISOString()
      }));
    }

    await prisma.sourceHealth.upsert({
      where: { source: sourceHost },
      create: {
        source: sourceHost,
        successCount: newSuccessCount,
        errorCount: newErrorCount,
        lastSuccessAt: result.success ? new Date() : null,
        lastErrorAt: !result.success ? new Date() : null,
        avgResponseMs: newAvgResponse,
        score: newScore,
        status: newStatus,
      },
      update: {
        successCount: newSuccessCount,
        errorCount: newErrorCount,
        lastSuccessAt: result.success ? new Date() : undefined,
        lastErrorAt: !result.success ? new Date() : undefined,
        avgResponseMs: newAvgResponse,
        score: newScore,
        status: newStatus,
      }
    });

  } catch (err: unknown) {
    log.error(`Fallo escribiendo source health para ${sourceHost}: ${getErrorMessage(err)}`);
  }
}

export async function shouldSkipSource(sourceHost: string): Promise<{ skip: boolean; reason?: string }> {
  const health = await prisma.sourceHealth.findUnique({ where: { source: sourceHost } });
  if (!health) return { skip: false };

  if (health.status === 'critical') {
    const SIX_HOURS_MS = 6 * 60 * 60 * 1000;
    if (health.lastErrorAt && Date.now() - health.lastErrorAt.getTime() < SIX_HOURS_MS) {
      log.info(JSON.stringify({ 
        event: "source_blocked", 
        source: sourceHost, 
        message: "Bloqueo por penalización Crítica en enfriamiento (6h)" 
      }));
      return { skip: true, reason: 'CRITICAL_COOLDOWN' };
    } else {
      log.info(JSON.stringify({ 
        event: "source_auto_recovery", 
        source: sourceHost, 
        message: "Período de enfriamiento superado. Intentando recovery." 
      }));
      return { skip: false };
    }
  }

  return { skip: false };
}

/**
 * scheduler.core.ts — v2
 *
 * Cambio principal respecto a v1:
 *   v1: reparseCount > 0 → PARSE_ONLY → discovery DESACTIVADO
 *       Consecuencia: fuentes con deuda de reparse nunca descubrían contenido nuevo
 *       (detectado con audit-coverage.ts el 2026-04-30: Idartes perdía 11 URLs nuevas,
 *        Sec. Cultura perdía 15).
 *
 *   v2: PARSE_ONLY ya no se auto-asigna por deuda de reparse.
 *       Discovery SIEMPRE ocurre. El reparse se ejecuta como una fase adicional
 *       al final del run, controlado por el campo `reparseCount` en SchedulePlan.
 *       Budget = discovery_cost + reparse_cost (combinado, capped a 20 URLs de reparse).
 *
 * Archivos de referencia:
 *   Backup v1: scheduler.core.v1.ts / scheduler.types.v1.ts
 */
import { Mode, SourceStats, SchedulePlan } from './scheduler.types';
import { createLogger } from '../../../lib/logger';

const log = createLogger('scraping:scheduler');

export const DEPTH: Record<Mode, { maxUrls: number }> = {
  DEEP:       { maxUrls: 40 },
  SURFACE:    { maxUrls: 15 },
  PING:       { maxUrls: 5  },
  PARSE_ONLY: { maxUrls: Infinity }, // Reservado para uso manual / backward-compat
};

/** Máximo de URLs de reparse a procesar por fuente por run (evita que reparse devore budget) */
const MAX_REPARSE_PER_RUN = 20;

/**
 * v2: Selecciona el modo de DISCOVERY para una fuente.
 *
 * PARSE_ONLY ya NO se retorna automáticamente cuando hay reparseCount.
 * El reparse ocurre como fase adicional independientemente del modo de discovery.
 */
export function pickMode(s: SourceStats): Mode {
  // Penalización a fuentes devoradoras de cuota sin retorno
  if (s.avgCost > 80 && s.saveRate < 0.1) return 'SURFACE';

  // Boost de eficiencia a fuentes orgánicamente limpias
  if (s.saveRate > 0.3 && s.avgCost < 30) return 'DEEP';

  // Conversión pura probada por usuarios
  if (s.ctr7d >= 0.20 && s.health >= 0.7) return 'DEEP';

  // Fuentes problemáticas → PING (solo exploración mínima)
  if (s.health < 0.4 || s.saveRate < 0.05) return 'PING';

  return 'SURFACE';
}

/**
 * Estima el costo combinado (discovery + reparse) para presupuesto de Gemini.
 *
 * Discovery: maxUrls * 1.5 (1 llamada discovery + 0.5 preflight por URL)
 * Reparse:   min(reparseCount, MAX_REPARSE_PER_RUN) * 1 (1 llamada por URL)
 */
export function estimateCost(maxUrls: number, mode: Mode, reparseCount: number = 0): number {
  if (mode === 'PARSE_ONLY') {
    // Backward-compat: PARSE_ONLY puro (sin discovery) solo cuenta reparse
    return Math.min(reparseCount, MAX_REPARSE_PER_RUN) * 1;
  }
  const discoveryCost = maxUrls * 1.5;
  const reparseCost   = Math.min(reparseCount, MAX_REPARSE_PER_RUN) * 1;
  return discoveryCost + reparseCost;
}

export interface PlanResult {
  planned: SchedulePlan[];
  skipped: { source: any; mode: Mode; reason: string }[];
  budgetUsed: number;
}

/**
 * v2: Resuelve la estrategia de extracción para una lista de fuentes.
 *
 * Orden de prioridad (dicta en qué se gasta primero el presupuesto):
 *   1. DEEP   — fuentes de alto rendimiento probado
 *   2. SURFACE — mantenimiento estándar
 *   3. PING   — exploración mínima / fuentes problemáticas
 *
 * El reparse ya no tiene prioridad propia: va montado sobre el modo de discovery
 * como costo adicional. Si no hay budget para el reparse, se hace discovery solo.
 */
export function buildPredictivePlan(
  sources: { source: any; stats: SourceStats }[],
  totalBudget: number
): PlanResult {
  const plan: SchedulePlan[] = [];
  const skipped: PlanResult['skipped'] = [];

  let budgetRemaining = totalBudget;
  const maxBudgetPerSource = 0.25 * totalBudget;

  // Prioridad de discovery: DEEP primero (mayor valor), luego SURFACE, luego PING
  const modePriority: Record<Mode, number> = { DEEP: 1, SURFACE: 2, PING: 3, PARSE_ONLY: 4 };

  const ordered = [...sources].sort((a, b) => {
    const aMode = pickMode(a.stats);
    const bMode = pickMode(b.stats);
    return modePriority[aMode] - modePriority[bMode];
  });

  for (const item of ordered) {
    const { source, stats } = item;
    const mode    = pickMode(stats);
    const maxUrls = DEPTH[mode].maxUrls;

    // Calcular reparse capped para esta fuente
    const reparseCount = Math.min(stats.reparseCount, MAX_REPARSE_PER_RUN);

    // Costo combinado discovery + reparse
    const fullCost = estimateCost(maxUrls, mode, stats.reparseCount);

    if (fullCost > budgetRemaining) {
      // Intentar sin reparse si discovery solo cabe
      const discoverOnlyCost = maxUrls * 1.5;
      if (discoverOnlyCost <= budgetRemaining) {
        // Discovery sin reparse: preferible a saltarse la fuente
        plan.push({ source, mode, maxUrls, estimatedCost: discoverOnlyCost, reparseCount: 0 });
        budgetRemaining -= discoverOnlyCost;
        log.info(`[PLAN] ${source.name}: reparse omitido por budget (discovery_only=${discoverOnlyCost})`);
      } else {
        skipped.push({ source, mode, reason: `Excede budget (req: ${fullCost}, rem: ${budgetRemaining})` });
      }
      continue;
    }

    if (fullCost > maxBudgetPerSource) {
      skipped.push({ source, mode, reason: `Excede maxBudgetPerSource 25% (req: ${fullCost})` });
      continue;
    }

    plan.push({ source, mode, maxUrls, estimatedCost: fullCost, reparseCount });
    budgetRemaining -= fullCost;
  }

  log.info(
    `Plan generado: ${plan.length} fuentes, ` +
    `Presupuesto consumido estimado: ${totalBudget - budgetRemaining} / ${totalBudget}`
  );

  return {
    planned: plan,
    skipped,
    budgetUsed: totalBudget - budgetRemaining,
  };
}

import { Mode, SourceStats, SchedulePlan } from './scheduler.types';
import { createLogger } from '../../../lib/logger';

const log = createLogger('scraping:scheduler');

export const DEPTH: Record<Mode, { maxUrls: number }> = {
  DEEP: { maxUrls: 40 },
  SURFACE: { maxUrls: 15 },
  PING: { maxUrls: 5 },
  PARSE_ONLY: { maxUrls: Infinity },
};

/**
 * Selecciona el modo de extracción para una fuente basada en histórico.
 */
export function pickMode(s: SourceStats): Mode {
  if (s.reparseCount > 0) return 'PARSE_ONLY';

  // Penalización a fuentes devoradoras de cuota sin retorno
  if (s.avgCost > 80 && s.saveRate < 0.1) {
    return 'SURFACE';
  }

  // Boost de eficiencia a fuentes orgánicamente limpias
  if (s.saveRate > 0.3 && s.avgCost < 30) {
    return 'DEEP';
  }

  // Conversión pura probada por usuarios
  if (s.ctr7d >= 0.20 && s.health >= 0.7) return 'DEEP';

  // Fuentes problemáticas mitigadas a PING.
  // NOTA isGov eliminado de esta condición: muchas de nuestras mejores fuentes son
  // gubernamentales (BibloRed, Idartes, Banrep). Antes `|| s.isGov` las mandaba a
  // PING independientemente de su rendimiento. Ahora solo penaliza health o saveRate.
  if (s.health < 0.4 || s.saveRate < 0.05) return 'PING';

  return 'SURFACE';
}

/**
 * Estima el costo (calls / Gemini) según el modo y límite.
 */
export function estimateCost(maxUrls: number, mode: Mode, reparseCount: number = 0): number {
  if (mode === 'PARSE_ONLY') {
    // 1 token por reparse (pipeline sin discovery)
    return reparseCount * 1;
  }
  
  // Para operaciones con discovery, estimamos 1 llamada para discovery y 0.5 llamada para filter pre-flight parse
  return maxUrls * 1.5;
}

export interface PlanResult {
  planned: SchedulePlan[];
  skipped: { source: any; mode: Mode; reason: string }[];
  budgetUsed: number;
  budgetWasted?: number;
}

/**
 * Resuelve la estrategia de extracción dada una lista de fuentes y el presupuesto diario de Gemini disponibles.
 */
export function buildPredictivePlan(
  sources: { source: any; stats: SourceStats }[],
  totalBudget: number
): PlanResult {
  const plan: SchedulePlan[] = [];
  const skipped: PlanResult['skipped'] = [];

  let budgetRemaining = totalBudget;
  const maxBudgetPerSource = 0.25 * totalBudget;
  const maxReparseBudget = 0.3 * totalBudget;
  let reparseBudgetUsed = 0;

  // Optimización de orden: la prioridad dicta en qué se gasta primero el presupuesto de Gemini (importante si la cuota es escasa).
  // 1. PARSE_ONLY (Recuperar la deuda que bajó el score del source)
  // 2. DEEP (Conversión real, nos pagan indirectamente por esto)
  // 3. SURFACE (Mantener fresco lo normal)
  // 4. PING (Ver si volvieron los zombies)
  const modePriority = { PARSE_ONLY: 1, DEEP: 2, SURFACE: 3, PING: 4 };

  // Copia modificable para iterar segura, asumiendo sources con estadísticas listadas.
  const ordered = [...sources].sort((a, b) => {
    const aMode = pickMode(a.stats);
    const bMode = pickMode(b.stats);
    return modePriority[aMode] - modePriority[bMode];
  });

  for (const item of ordered) {
    const { source, stats } = item;
    const mode = pickMode(stats);
    let maxUrls = DEPTH[mode].maxUrls;
    
    if (mode === 'PARSE_ONLY') {
      maxUrls = stats.reparseCount;
    }
    
    const cost = estimateCost(maxUrls, mode, stats.reparseCount);

    if (cost > budgetRemaining) {
      skipped.push({ source, mode, reason: `Excede budget local (req: ${cost}, rem: ${budgetRemaining})` });
      continue;
    }

    if (cost > maxBudgetPerSource && mode !== 'PARSE_ONLY') {
      // Degradar modo si excede su capa máxima y no es una recuperación nativa de parse
      // (ej. un DEEP muy ambicioso en fuente carísima).
      skipped.push({ source, mode, reason: `Excede maxBudgetPerSource 25% (req: ${cost})` });
      continue; 
    }

    if (mode === 'PARSE_ONLY') {
       if ((reparseBudgetUsed + cost) > maxReparseBudget) {
         skipped.push({ source, mode, reason: `Excede bucket maxReparseBudget 30%` });
         continue;
       }
       reparseBudgetUsed += cost;
    }

    plan.push({
      source,
      mode,
      maxUrls,
      estimatedCost: cost
    });
    budgetRemaining -= cost;
  }

  log.info(`Plan generado: ${plan.length} fuentes, Presupuesto consumido estimado: ${totalBudget - budgetRemaining} / ${totalBudget}`);

  return {
    planned: plan,
    skipped,
    budgetUsed: totalBudget - budgetRemaining
  };
}

export type Mode = 'DEEP' | 'SURFACE' | 'PING' | 'PARSE_ONLY';

export interface SourceStats {
  /** Source URL hostname (sin www) o alias de BD */
  sourceId: string;
  /** CTR real calculado (clicks / views) en los últimos 7 días */
  ctr7d: number;
  /** Promedio histórico de actividades guardadas / URLs descubiertas en % */
  saveRate: number;
  /** Health score actual de la base de datos (0-1) */
  health: number;
  /** Promedio de llamadas consumidas (Gemini tokens/costs) en las últimas 5 corridas */
  avgCost: number;
  /** Cantidad de URLs de la fuente en cache marcadas con needsReparse */
  reparseCount: number;
  /** Indica si la URL pertenece a dependencias gubernamentales (isGov = true) */
  isGov: boolean;
}

export interface SchedulePlan {
  /** Fuente objetivo que entrará al pipeline */
  source: any; // Se reemplazará con el modelo Source en ingest-sources.ts
  /** Modo predictivo seleccionado por la heurística (DEEP/SURFACE/PING para discovery) */
  mode: Mode;
  /** Cantidad de URLs a descubrir (capped por presupuesto disponible) */
  maxUrls: number;
  /** Profundidad estimada en costos de LLM (discovery + reparse combinados) */
  estimatedCost: number;
  /**
   * v2: Cantidad de URLs con needsReparse a procesar DESPUÉS del discovery.
   * undefined / 0 = sin deuda de reparse en este run.
   *
   * Cambio clave respecto a v1:
   * - v1: reparseCount > 0 → modo PARSE_ONLY → discovery desactivado completamente
   * - v2: reparseCount > 0 → discovery ocurre normalmente + reparse se ejecuta al final
   *       El resultado: nunca se pierde contenido nuevo por tener deuda de reparse.
   */
  reparseCount?: number; // undefined = 0 (backward-compat con v1)
}

export type Mode = 'DEEP' | 'SURFACE' | 'PING' | 'PARSE_ONLY';

export interface SourceStats {
  /** Source URL hostname (sin www) o alias de BD */
  sourceId: string;
